# Dijkstra's Shortest Path Algorithm

## Conceptual Overview

Dijkstra's algorithm finds the **shortest path from a source node to all other nodes** in a weighted graph with non-negative edge weights.

### Core Idea

The algorithm works on a simple greedy principle:

> *"At each step, visit the unvisited node with the currently known shortest distance from the source, then update its neighbors."*

### Step-by-Step Process

```
1. Initialize distances: source = 0, all others = Infinity
2. Mark all nodes as unvisited
3. Set source as the current node
4. For the current node:
   - Calculate tentative distances to each unvisited neighbor
     (current distance + edge weight)
   - If tentative distance < known distance, update it
5. Mark current node as visited (never revisit it)
6. Select the unvisited node with the smallest known distance → new current
7. Repeat steps 4–6 until all nodes are visited (or target is reached)
```

### Why It Works

- Once a node is marked visited, we've found its **guaranteed shortest path**
- This holds because all edge weights are non-negative — you can never find a
  shorter path by going through a node with a larger distance
- It's a **greedy algorithm** that makes the locally optimal choice at each step,
  which produces the globally optimal result

### Complexity

| Structure | Time | Space |
|---|---|---|
| Naive (array) | O(V²) | O(V) |
| Binary heap (priority queue) | O((V + E) log V) | O(V) |
| Fibonacci heap | O(E + V log V) | O(V) |

> V = vertices, E = edges

---

## TypeScript Implementation

```typescript
// ─── Types ───────────────────────────────────────────────────────────────────

interface Edge {
  to: number;
  weight: number;
}

interface ShortestPathResult {
  distances: number[];       // distances[i] = shortest distance from source to i
  previous: (number | null)[]; // previous[i] = preceding node on shortest path
}

// ─── Min-Heap Priority Queue ──────────────────────────────────────────────────
// Stores [distance, nodeId] pairs, ordered by distance (ascending)

class MinHeap {
  private heap: [number, number][] = [];

  get size(): number {
    return this.heap.length;
  }

  push(item: [number, number]): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): [number, number] | undefined {
    if (this.heap.length === 0) return undefined;
    const top = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent][0] <= this.heap[i][0]) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const length = this.heap.length;
    while (true) {
      const left  = 2 * i + 1;
      const right = 2 * i + 2;
      let smallest = i;

      if (left  < length && this.heap[left][0]  < this.heap[smallest][0]) smallest = left;
      if (right < length && this.heap[right][0] < this.heap[smallest][0]) smallest = right;

      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

/**
 * Finds shortest paths from `source` to all nodes in a weighted directed graph.
 *
 * @param graph   Adjacency list: graph[u] = array of { to, weight } edges
 * @param source  Starting node index
 * @returns       Distances and predecessor map for path reconstruction
 */
function dijkstra(graph: Edge[][], source: number): ShortestPathResult {
  const n = graph.length;
  const distances = new Array<number>(n).fill(Infinity);
  const previous  = new Array<number | null>(n).fill(null);
  const visited   = new Array<boolean>(n).fill(false);

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push([0, source]); // [distance, node]

  while (pq.size > 0) {
    const [currentDist, u] = pq.pop()!;

    // Skip if we already found a better path to this node
    if (visited[u]) continue;
    visited[u] = true;

    // Explore neighbors
    for (const { to: v, weight } of graph[u]) {
      if (visited[v]) continue;

      const newDist = currentDist + weight;
      if (newDist < distances[v]) {
        distances[v] = newDist;
        previous[v]  = u;
        pq.push([newDist, v]);
      }
    }
  }

  return { distances, previous };
}

// ─── Path Reconstruction ──────────────────────────────────────────────────────

/**
 * Reconstructs the shortest path from source to target using the `previous` map.
 */
function reconstructPath(
  previous: (number | null)[],
  source: number,
  target: number
): number[] | null {
  const path: number[] = [];
  let current: number | null = target;

  while (current !== null) {
    path.unshift(current);
    if (current === source) return path;
    current = previous[current];
  }

  return null; // No path exists
}

