  distances: number[];       // distances[i] = shortest distance from source to i
  previous: (number | null)[]; // for path reconstruction
}

// ─── Min-Heap (Priority Queue) ────────────────────────────────────────────────

interface HeapNode {
  node: number;
  distance: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  push(item: HeapNode): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent].distance <= this.heap[i].distance) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left  = 2 * i + 1;
      const right = 2 * i + 2;

      if (left  < n && this.heap[left].distance  < this.heap[smallest].distance) smallest = left;
      if (right < n && this.heap[right].distance < this.heap[smallest].distance) smallest = right;

      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Graph ────────────────────────────────────────────────────────────────────

class Graph {
  private adjacencyList: Edge[][];

  constructor(public readonly vertexCount: number) {
    this.adjacencyList = Array.from({ length: vertexCount }, () => []);
  }

  /** Add a directed edge from -> to with given weight */
  addEdge(from: number, to: number, weight: number): void {
    if (weight < 0) throw new Error("Dijkstra requires non-negative edge weights.");
    this.adjacencyList[from].push({ to, weight });
  }

  /** Add an undirected edge (both directions) */
  addUndirectedEdge(u: number, v: number, weight: number): void {
    this.addEdge(u, v, weight);
    this.addEdge(v, u, weight);
  }

  neighbors(node: number): Edge[] {
    return this.adjacencyList[node];
  }
}

// ─── Dijkstra ─────────────────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: number): ShortestPathResult {
  const n = graph.vertexCount;
  const distances = new Array<number>(n).fill(Infinity);
  const previous  = new Array<number | null>(n).fill(null);
  const visited   = new Array<boolean>(n).fill(false);

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push({ node: source, distance: 0 });

  while (pq.size > 0) {
    const { node: u, distance: distU } = pq.pop()!;

    // Stale entry — a shorter path was already found
    if (visited[u]) continue;
    visited[u] = true;

    // Early termination: all reachable nodes are settled
    // (optional; remove if you need all distances)
    if (distU === Infinity) break;

    for (const { to: v, weight } of graph.neighbors(u)) {
      if (visited[v]) continue;

      const newDist = distances[u] + weight;
      if (newDist < distances[v]) {
        distances[v] = newDist;
        previous[v]  = u;
        pq.push({ node: v, distance: newDist });
      }
    }
  }

  return { distances, previous };
}

// ─── Path Reconstruction ──────────────────────────────────────────────────────

function reconstructPath(
  previous: (number | null)[],
  source: number,
  target: number
): number[] | null {
  const path: number[] = [];
  let current: number | null = target;

  while (current !== null) {
    path.unshift(current);
    if (current === source) return path;
    current = previous[current];
  }

  return null; // target not reachable
}

