# Dijkstra's Shortest Path Algorithm

## Conceptual Overview

### The Core Idea
Dijkstra's algorithm finds the **shortest path from a source node to all other nodes** in a weighted graph (with non-negative edge weights). It works by greedily expanding the nearest unvisited node at each step.

### Mental Model: Ripples in a Pond
Imagine dropping a stone in water. Ripples expand outward — closer areas are reached first, farther areas later. Dijkstra works the same way: it "settles" nodes in order of their distance from the source.

### Key Data Structures
| Structure | Purpose |
|-----------|---------|
| **Distance map** | Tracks best-known distance to each node |
| **Priority queue (min-heap)** | Always processes the nearest unvisited node next |
| **Visited set** | Prevents reprocessing settled nodes |
| **Previous map** | Reconstructs the actual path |

---

### Step-by-Step Process

```
1. Initialize all distances to ∞, except source = 0
2. Add source to priority queue with priority 0
3. While queue is not empty:
   a. Pop node with SMALLEST distance (u)
   b. If already visited, skip
   c. Mark u as visited
   d. For each neighbor (v) of u:
      - newDist = dist[u] + weight(u, v)
      - If newDist < dist[v]:
          • Update dist[v] = newDist
          • Record prev[v] = u
          • Push v into priority queue
4. Return distances and previous-node map
```

### Why Greedy Works Here
Once a node is settled (popped from the min-heap), its distance is **final** — no future path through non-negative weights can improve it. This is the invariant that makes the greedy approach correct.

### Complexity
| Case | Time | Space |
|------|------|-------|
| With binary heap | O((V + E) log V) | O(V) |
| With Fibonacci heap | O(E + V log V) | O(V) |
| Naive array scan | O(V²) | O(V) |

---

## TypeScript Implementation

```typescript
// ─────────────────────────────────────────────
// Types
// ─────────────────────────────────────────────

type NodeId = string | number;

interface Edge {
  to: NodeId;
  weight: number;
}

interface Graph {
  [node: NodeId]: Edge[];
}

interface DijkstraResult {
  distances: Map<NodeId, number>;
  previous:  Map<NodeId, NodeId | null>;
  getPath:   (target: NodeId) => NodeId[];
}

// ─────────────────────────────────────────────
// Min-Heap Priority Queue
// ─────────────────────────────────────────────

interface HeapNode {
  id:       NodeId;
  priority: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  push(id: NodeId, priority: number): void {
    this.heap.push({ id, priority });
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.isEmpty()) return undefined;

    const top = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return top;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent].priority <= this.heap[index].priority) break;
      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left  = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left  < length && this.heap[left].priority  < this.heap[smallest].priority) smallest = left;
      if (right < length && this.heap[right].priority < this.heap[smallest].priority) smallest = right;

      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// ─────────────────────────────────────────────
// Dijkstra's Algorithm
// ─────────────────────────────────────────────

function dijkstra(graph: Graph, source: NodeId): DijkstraResult {
  const distances = new Map<NodeId, number>();
  const previous  = new Map<NodeId, NodeId | null>();
  const visited   = new Set<NodeId>();
  const queue     = new MinHeap();

  // ── Initialize all nodes ──────────────────
  for (const node of Object.keys(graph)) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }

  // ── Source node setup ─────────────────────
  distances.set(source, 0);
  queue.push(source, 0);

  // ── Main loop ─────────────────────────────
  while (!queue.isEmpty()) {
    const { id: current, priority: currentDist } = queue.pop()!;

    // Skip if already settled (stale heap entry)
    if (visited.has(current)) continue;
    visited.add(current);

    // Early exit if popped distance exceeds known best
    if (currentDist > (distances.get(current) ?? Infinity)) continue;

    const neighbors = graph[current] ?? [];

    for (const { to, weight } of neighbors) {
      if (visited.has(to)) continue;

      if (weight < 0) {
        throw new Error(
          `Negative edge weight detected: ${String(current)} → ${String(to)} (${weight}). ` +
          `Use Bellman-Ford for graphs with negative weights.`
        );
      }

      const newDist = (distances.get(current) ?? Infinity) + weight;

      if (newDist < (distances.get(to) ?? Infinity)) {
        distances.set(to, newDist);
        previous.set(to, current);
        queue.push(to, newDist);
      }
    }
  }

  // ── Path reconstruction helper ────────────
  function getPath(target: NodeId): NodeId[] {
    const path: NodeId[] = [];
    let current: NodeId | null | undefined = target;

    if (!distances.has(target) || distances.get(target) === Infinity) {
      return []; // No path exists
    }

    while (current != null) {
      path.unshift(current);
      current = previous.get(current);
    }

    // Validate path starts at source
