  const distances = new Map<string, number>();
  const previous = new Map<string, string | null>();
  const visited = new Set<string>();

  // Min-heap: [distance, node]
  const heap: Array<[number, string]> = [];

  for (const node of graph.keys()) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }
  distances.set(source, 0);
  heap.push([0, source]);

  while (heap.length > 0) {
    heap.sort(([a], [b]) => a - b); // replace with proper heap in prod
    const [dist, node] = heap.shift()!;

    if (visited.has(node)) continue;
    visited.add(node);

    for (const { to, weight } of graph.get(node) ?? []) {
      const candidate = dist + weight;
      if (candidate < distances.get(to)!) {
        distances.set(to, candidate);
        previous.set(to, node);
        heap.push([candidate, to]);
      }
    }
  }

  return { distances, previous };
}

