# Dijkstra's Algorithm: Finding the Shortest Path

## The Conceptual Metaphor

Imagine you're lost in a city, and you want the fastest route home. You don't have a map — only a radio that locals use to shout out distances between intersections.

Your strategy:
1. **Start at your current corner.** Your distance to yourself is zero. Every other corner? Assume infinity — you simply don't know yet.
2. **Always visit the closest unvisited corner next.** This is the algorithm's soul — *greedy optimism*. The nearest unexplored place can only get farther, never closer.
3. **Relax your neighbors.** When you visit a corner, check if going *through it* gives any neighbor a shorter path than what they currently believe. If so, update them.
4. **Repeat until you reach home** — or exhaust the map.

The key insight is **permanence**: once a node is visited, its shortest distance is *locked in forever*. No future discovery can improve it, because you always process the minimum first.

> Think of it like water flowing downhill — it always finds the lowest point first, and once it settles, it doesn't rise back up.

---

## The TypeScript Implementation

```typescript
// ─── Types ────────────────────────────────────────────────────────────────────

type NodeId = string | number;

interface Edge {
  to: NodeId;
  weight: number;
}

interface Graph {
  [node: NodeId]: Edge[];
}

interface DijkstraResult {
  distances: Record<NodeId, number>;
  previous: Record<NodeId, NodeId | null>;
  getPath: (target: NodeId) => NodeId[];
}

// ─── Min-Priority Queue ───────────────────────────────────────────────────────
// The engine that always surfaces the closest unvisited node.

class MinPriorityQueue {
  private heap: [number, NodeId][] = []; // [priority, nodeId]

  enqueue(node: NodeId, priority: number): void {
    this.heap.push([priority, node]);
    this.bubbleUp(this.heap.length - 1);
  }

  dequeue(): [number, NodeId] | undefined {
    if (this.heap.length === 0) return undefined;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  get isEmpty(): boolean {
    return this.heap.length === 0;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent][0] <= this.heap[index][0]) break;
      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;
    while (true) {
      const left = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left < length && this.heap[left][0] < this.heap[smallest][0])
        smallest = left;
      if (right < length && this.heap[right][0] < this.heap[smallest][0])
        smallest = right;
      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: NodeId): DijkstraResult {
  const distances: Record<NodeId, number> = {};
  const previous: Record<NodeId, NodeId | null> = {};
  const visited = new Set<NodeId>();
  const pq = new MinPriorityQueue();

  // Initialize: every node is infinitely far away
  for (const node in graph) {
    distances[node] = Infinity;
    previous[node] = null;
  }

  // The source knows itself — distance zero
  distances[source] = 0;
  pq.enqueue(source, 0);

  while (!pq.isEmpty) {
    const dequeued = pq.dequeue()!;
    const [currentDist, current] = dequeued;

    // Skip if we've already locked in a shorter path (stale entry)
    if (visited.has(current)) continue;
    visited.add(current);

    // Early exit optimization: if processing a node already worse, skip
    if (currentDist > distances[current]) continue;

    // Relax each neighbor — can we offer them a shorter route through us?
    for (const edge of graph[current] ?? []) {
      if (visited.has(edge.to)) continue;

      const candidate = distances[current] + edge.weight;

      if (candidate < distances[edge.to]) {
        distances[edge.to] = candidate;
        previous[edge.to] = current;
        pq.enqueue(edge.to, candidate);
      }
    }
  }

  // Reconstruct the path from source to any target by walking backwards
  function getPath(target: NodeId): NodeId[] {
    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
      // Guard: if we can't trace back to source, no path exists
      if (current !== null && distances[current] === Infinity) return [];
    }

    return path[0] === source ? path : [];
  }

  return { distances, previous, getPath };
}

