    while (true) {
      const left  = 2 * idx + 1;
      const right = 2 * idx + 2;
      let smallest = idx;

      if (left  < length && this.heap[left].priority  < this.heap[smallest].priority) smallest = left;
      if (right < length && this.heap[right].priority < this.heap[smallest].priority) smallest = right;

