function dijkstra(graph: Graph, source: NodeId): DijkstraResult {
  const distances = new Map<NodeId, number>();
  const previous  = new Map<NodeId, NodeId | null>();
  const visited   = new Set<NodeId>();
  const queue     = new MinHeap();

  // ── Initialize all known nodes to Infinity ──────────────
  for (const node of Object.keys(graph)) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }

  // ── Source node costs nothing to reach ──────────────────
  distances.set(source, 0);
  queue.push({ id: source, priority: 0 });

  // ── Main loop ────────────────────────────────────────────
  while (queue.size > 0) {
    const current = queue.pop()!;
    const { id: u } = current;

    // Lazy deletion: skip if we've already settled this node
    if (visited.has(u)) continue;
    visited.add(u);

    const neighbors = graph[u] ?? [];

    for (const { to: v, weight: w } of neighbors) {
      if (visited.has(v)) continue;
      if (w < 0) throw new Error(`Negative weight on edge ${String(u)}→${String(v)}`);

      const candidate = distances.get(u)! + w;

      if (candidate < (distances.get(v) ?? Infinity)) {
        distances.set(v, candidate);
        previous.set(v, u);
        queue.push({ id: v, priority: candidate });   // lazy: old entry stays but gets skipped
      }
    }
  }

  // ── Path reconstruction helper ───────────────────────────
  function getPath(target: NodeId): NodeId[] | null {
    if (!distances.has(target) || distances.get(target) === Infinity) {
      return null; // unreachable
    }

    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous.get(current) ?? null;
    }

    // Validate the path actually starts at source
    return path[0] === source ? path : null;
  }

  return { distances, previous, getPath };
}

// ============================================================
// Helper: Build an undirected graph from an edge list
// ============================================================

function buildGraph(
  edges: Array<[NodeId, NodeId, number]>,
  directed = false
): Graph {
  const graph: Graph = {};

  for (const [u, v, w] of edges) {
    if (!graph[u]) graph[u] = [];
    if (!graph[v]) graph[v] = [];

    graph[u].push({ to: v, weight: w });
    if (!directed) graph[v].push({ to: u, weight: w });
  }

  return graph;
}

