  for (const node in graph) {
    distances[node] = Infinity;
    previous[node] = null;
  }

  // Source node costs nothing to reach
  distances[source] = 0;
  pq.push({ node: source, distance: 0 });

  while (pq.size > 0) {
    const { node: current, distance: currentDist } = pq.pop()!;

    // Skip stale heap entries (lazy deletion)
    if (visited.has(current)) continue;
    visited.add(current);

    // No point exploring if we can't improve
    if (currentDist > distances[current]) continue;

    for (const { to: neighbor, weight } of graph[current] ?? []) {
