      // Cycle guard (shouldn't happen with valid input)
      if (path.length > Object.keys(graph).length + 1) {
        throw new Error("Cycle detected during path reconstruction");
      }
    }

    // If path doesn't start at source, target is unreachable
    return path[0] === source ? path : [];
  }

  return { distances, previous, getPath };
}

