    const entry = pq.extractMin();
    if (!entry) break;

    const [currentDist, currentNode] = entry;

    // Skip if already processed (stale entry in heap)
    if (visited.has(currentNode)) continue;
    visited.add(currentNode);

    // If we pulled a stale/irrelevant distance, skip
    if (currentDist > distances[currentNode]) continue;

    // Relax all neighboring edges
    for (const edge of graph[currentNode] ?? []) {
      if (visited.has(edge.to)) continue;

      const candidate = distances[currentNode] + edge.weight;

      if (candidate < distances[edge.to]) {
        distances[edge.to] = candidate;
        previous[edge.to] = currentNode;
        pq.insert(candidate, edge.to);
      }
    }
  }

  // Reconstruct path from source to any target
  const getPath = (target: string): string[] => {
    const path: string[] = [];
    let current: string | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
      // If we've reached a node with no predecessor and it's not the source, path is broken
      if (current !== null && previous[current] === undefined && current !== source) {
        return []; // unreachable
      }
    }

    // Valid path must start at source
    return path[0] === source ? path : [];
  };

  return { distances, previous, getPath };
