```typescript
// ============================================================
// Dijkstra's Shortest Path Algorithm - TypeScript Implementation
// ============================================================

// --- Type Definitions ---

interface Edge {
  to: number;
  weight: number;
}

interface Graph {
  [node: number]: Edge[];
}

interface DijkstraResult {
  distances: Map<number, number>;
  predecessors: Map<number, number | null>;
  getPath: (target: number) => number[] | null;
}

// --- Min-Heap (Priority Queue) Implementation ---

class MinHeap {
  private heap: [number, number][] = []; // [distance, node]

  get size(): number {
    return this.heap.length;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  push(item: [number, number]): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): [number, number] | undefined {
    if (this.isEmpty()) return undefined;

    const top = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return top;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.heap[parentIndex][0] <= this.heap[index][0]) break;

      [this.heap[parentIndex], this.heap[index]] = [
        this.heap[index],
        this.heap[parentIndex],
      ];
      index = parentIndex;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left < length && this.heap[left][0] < this.heap[smallest][0]) {
        smallest = left;
      }
      if (right < length && this.heap[right][0] < this.heap[smallest][0]) {
        smallest = right;
      }

      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [
        this.heap[index],
        this.heap[smallest],
      ];
      index = smallest;
    }
  }
}

// --- Dijkstra's Algorithm ---

function dijkstra(graph: Graph, source: number): DijkstraResult {
  const distances = new Map<number, number>();
  const predecessors = new Map<number, number | null>();
  const visited = new Set<number>();
  const pq = new MinHeap();

  // Initialize all distances to Infinity
  for (const node in graph) {
    const nodeNum = Number(node);
    distances.set(nodeNum, Infinity);
    predecessors.set(nodeNum, null);
  }

  // Source node has distance 0
  distances.set(source, 0);
  pq.push([0, source]);

  while (!pq.isEmpty()) {
    const entry = pq.pop();
    if (!entry) break;

    const [currentDist, currentNode] = entry;

    // Skip if already visited (stale entry in heap)
    if (visited.has(currentNode)) continue;
    visited.add(currentNode);

    // If current distance is worse than recorded, skip
    if (currentDist > (distances.get(currentNode) ?? Infinity)) continue;

    // Relax all neighbors
    const neighbors = graph[currentNode] ?? [];
    for (const { to, weight } of neighbors) {
      if (visited.has(to)) continue;

      const newDist = currentDist + weight;
      const knownDist = distances.get(to) ?? Infinity;

      if (newDist < knownDist) {
        distances.set(to, newDist);
        predecessors.set(to, currentNode);
        pq.push([newDist, to]);
      }
    }
  }

  // Path reconstruction function
  function getPath(target: number): number[] | null {
    if (!distances.has(target) || distances.get(target) === Infinity) {
      return null; // No path exists
    }

    const path: number[] = [];
    let current: number | null = target;

    while (current !== null) {
      path.unshift(current);
      current = predecessors.get(current) ?? null;
    }

    // Verify path starts at source
    if (path[0] !== source) return null;

    return path;
  }

  return { distances, predecessors, getPath };
}

// --- Helper: Build an undirected graph ---

function buildGraph(
  nodes: number,
  edges: [number, number, number][] // [from, to, weight]
): Graph {
  const graph: Graph = {};

  for (let i = 0; i < nodes; i++) {
    graph[i] = [];
  }

  for (const [from, to, weight] of edges) {
    graph[from].push({ to, weight });
    graph[to].push({ to: from, weight }); // Undirected
  }

  return graph;
}

