## Dijkstra's Shortest-Path Algorithm

### Conceptual Explanation

Dijkstra's algorithm finds the shortest path from a single source node to all other nodes in a weighted graph with **non-negative edge weights**.

**Core idea — greedy expansion:**
1. Assign distance 0 to the source, infinity to all others.
2. Maintain a **priority queue** (min-heap) of nodes ordered by their current best-known distance.
3. At each step, pop the node with the smallest distance (the "cheapest" unvisited node).
4. For each of its neighbors, check if going *through* the current node gives a shorter path ("relaxation"). If so, update the neighbor's distance and push it into the queue.
5. Once a node is popped, its distance is finalized — no shorter path can exist because all weights are non-negative.
6. Repeat until the queue is empty.

**Why it works:** Because edge weights are non-negative, the first time a node is popped from the min-heap its distance is optimal. Any later path to it would be at least as long.

**Complexity:**
- With a binary min-heap: O((V + E) log V)
- With a Fibonacci heap: O(E + V log V)

---

### TypeScript Implementation

```typescript
type Edge = { to: number; weight: number };
type Graph = Map<number, Edge[]>;

// Minimal binary min-heap (priority queue)
class MinHeap {
  private heap: [number, number][] = []; // [distance, node]

  push(dist: number, node: number): void {
    this.heap.push([dist, node]);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): [number, number] | undefined {
    if (this.heap.length === 0) return undefined;
    const top = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  get size(): number {
    return this.heap.length;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = (i - 1) >> 1;
      if (this.heap[parent][0] <= this.heap[i][0]) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;
      if (left < n && this.heap[left][0] < this.heap[smallest][0]) smallest = left;
      if (right < n && this.heap[right][0] < this.heap[smallest][0]) smallest = right;
      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

/**
 * Dijkstra's algorithm.
 * @param graph  Adjacency list (node -> list of {to, weight})
 * @param source Starting node
 * @returns      Map of node -> shortest distance from source
 *               (and prev map for path reconstruction)
 */
function dijkstra(
  graph: Graph,
  source: number
): { dist: Map<number, number>; prev: Map<number, number | null> } {
  const dist = new Map<number, number>();
  const prev = new Map<number, number | null>();
  const visited = new Set<number>();
  const pq = new MinHeap();

  // Initialize all distances to Infinity
  for (const node of graph.keys()) {
    dist.set(node, Infinity);
    prev.set(node, null);
  }

  dist.set(source, 0);
  pq.push(0, source);

  while (pq.size > 0) {
    const [d, u] = pq.pop()!;

    if (visited.has(u)) continue; // stale entry
    visited.add(u);

    const neighbors = graph.get(u) ?? [];
    for (const { to: v, weight } of neighbors) {
      if (visited.has(v)) continue;
      const newDist = d + weight;
      if (newDist < (dist.get(v) ?? Infinity)) {
        dist.set(v, newDist);
        prev.set(v, u);
        pq.push(newDist, v);
      }
    }
  }

  return { dist, prev };
}

/** Reconstruct the shortest path from source to target using the prev map. */
function getPath(prev: Map<number, number | null>, target: number): number[] {
  const path: number[] = [];
  let cur: number | null = target;
  while (cur !== null && cur !== undefined) {
    path.unshift(cur);
    cur = prev.get(cur) ?? null;
  }
  return path;
}

