  ["D", [{ node: "E", weight: 2 }]],
  ["E", []],
]);

const { distances, path } = dijkstra(graph, "A", "E");

console.log("Shortest path:", path.join(" → "));        // A → C → B → D → E
console.log("Total cost:   ", distances.get("E"));      // 10
