// ─────────────────────────────────────────────

interface HeapNode {
  id:       NodeId;
  priority: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  push(id: NodeId, priority: number): void {
    this.heap.push({ id, priority });
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.isEmpty()) return undefined;

    const top = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return top;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent].priority <= this.heap[index].priority) break;
      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left  = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left  < length && this.heap[left].priority  < this.heap[smallest].priority) smallest = left;
      if (right < length && this.heap[right].priority < this.heap[smallest].priority) smallest = right;

      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// ─────────────────────────────────────────────
// Dijkstra's Algorithm
// ─────────────────────────────────────────────

function dijkstra(graph: Graph, source: NodeId): DijkstraResult {
  const distances = new Map<NodeId, number>();
  const previous  = new Map<NodeId, NodeId | null>();
  const visited   = new Set<NodeId>();
  const queue     = new MinHeap();

  // ── Initialize all nodes ──────────────────
  for (const node of Object.keys(graph)) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }

  // ── Source node setup ─────────────────────
  distances.set(source, 0);
  queue.push(source, 0);

  // ── Main loop ─────────────────────────────
  while (!queue.isEmpty()) {
    const { id: current, priority: currentDist } = queue.pop()!;

    // Skip if already settled (stale heap entry)
    if (visited.has(current)) continue;
    visited.add(current);

    // Early exit if popped distance exceeds known best
    if (currentDist > (distances.get(current) ?? Infinity)) continue;

    const neighbors = graph[current] ?? [];

    for (const { to, weight } of neighbors) {
      if (visited.has(to)) continue;

      if (weight < 0) {
        throw new Error(
          `Negative edge weight detected: ${String(current)} → ${String(to)} (${weight}). ` +
          `Use Bellman-Ford for graphs with negative weights.`
        );
      }

      const newDist = (distances.get(current) ?? Infinity) + weight;

      if (newDist < (distances.get(to) ?? Infinity)) {
        distances.set(to, newDist);
        previous.set(to, current);
        queue.push(to, newDist);
      }
    }
  }

  // ── Path reconstruction helper ────────────
  function getPath(target: NodeId): NodeId[] {
    const path: NodeId[] = [];
    let current: NodeId | null | undefined = target;

    if (!distances.has(target) || distances.get(target) === Infinity) {
      return []; // No path exists
    }

    while (current != null) {
      path.unshift(current);
      current = previous.get(current);
    }

    // Validate path starts at source
    return path[0] === source ? path : [];
  }

  return { distances, previous, getPath };
}

