// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: NodeId): ShortestPathResult {
  const distances: Record<NodeId, number> = {};
  const previous: Record<NodeId, NodeId | null> = {};
  const visited = new Set<NodeId>();
  const pq = new MinHeap();

  // Step 1: Initialize distances
  for (const node in graph) {
    distances[node] = node === String(source) ? 0 : Infinity;
    previous[node] = null;
  }

  pq.push({ id: source, priority: 0 });

  // Step 2: Process nodes
  while (pq.size > 0) {
    const current = pq.pop()!;
    const u = current.id;

    // Skip if already finalized (stale heap entry)
    if (visited.has(u)) continue;
    visited.add(u);

    const neighbors = graph[u] ?? [];

    for (const edge of neighbors) {
      const v = edge.to;
      if (visited.has(v)) continue;

      // Step 3: Relaxation
      const candidate = distances[u] + edge.weight;
      if (candidate < (distances[v] ?? Infinity)) {
        distances[v] = candidate;
        previous[v] = u;
        pq.push({ id: v, priority: candidate });
        // Note: we use "lazy deletion" — old entries are skipped via visited check
      }
    }
  }

  // Step 4: Path reconstruction helper
  function getPath(target: NodeId): NodeId[] {
    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
      // Detect if node was unreachable
      if (current !== null && !(current in previous)) break;
    }

    // Validate path starts from source
    if (path[0] !== source) return []; // unreachable
    return path;
  }

  return { distances, previous, getPath };
}

