# Dijkstra's Algorithm: Finding the Shortest Path

## The Conceptual Heart

Imagine you're a **rumor spreading through a city**. You start at one person and want to reach everyone else via the shortest chain of whispers. You always spread to your *nearest unvisited neighbor* first — because once you've reached someone via the shortest route, that route can never be beaten by a longer detour.

This is Dijkstra's insight: **greedy certainty**. At each step, the node with the smallest known distance is *permanently settled* — no future path through unvisited nodes could possibly improve it (assuming non-negative edge weights).

## The Three Core Ideas

```
1. DISCOVERY   — Start with ∞ distance to everyone, 0 to yourself
2. RELAXATION  — When visiting a node, ask: "Can I offer my neighbors
                  a cheaper route through me?"
3. COMMITMENT  — Once a node has the minimum tentative distance,
                  lock it in. It's done. Never revisit.
```

Think of it as **water filling a landscape** — flowing outward from the source, always finding the lowest channels first, settling in valleys permanently.

---

## TypeScript Implementation

```typescript
// ─────────────────────────────────────────────
//  Types
// ─────────────────────────────────────────────

type NodeId = string;

interface Edge {
  to: NodeId;
  weight: number;
}

interface Graph {
  [node: NodeId]: Edge[];
}

interface ShortestPathResult {
  distances: Record<NodeId, number>;
  previous:  Record<NodeId, NodeId | null>;
  getPath:   (target: NodeId) => NodeId[];
}

// ─────────────────────────────────────────────
//  Min-Priority Queue (binary heap)
//  A sorted queue so we always process the
//  cheapest unvisited node next — O(log n)
// ─────────────────────────────────────────────

interface PQNode {
  id:       NodeId;
  priority: number;
}

class MinPriorityQueue {
  private heap: PQNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  enqueue(id: NodeId, priority: number): void {
    this.heap.push({ id, priority });
    this.bubbleUp(this.heap.length - 1);
  }

  dequeue(): PQNode | undefined {
    if (this.heap.length === 0) return undefined;

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return min;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent].priority <= this.heap[i].priority) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const length = this.heap.length;
    while (true) {
      const left  = 2 * i + 1;
      const right = 2 * i + 2;
      let smallest = i;

      if (left  < length && this.heap[left].priority  < this.heap[smallest].priority) smallest = left;
      if (right < length && this.heap[right].priority < this.heap[smallest].priority) smallest = right;

      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─────────────────────────────────────────────
//  Dijkstra's Algorithm
// ─────────────────────────────────────────────

function dijkstra(graph: Graph, source: NodeId): ShortestPathResult {
  const distances: Record<NodeId, number>       = {};
  const previous:  Record<NodeId, NodeId | null> = {};
  const visited    = new Set<NodeId>();
  const pq         = new MinPriorityQueue();

  // 1. DISCOVERY — initialize all distances to infinity
  for (const node of Object.keys(graph)) {
    distances[node] = Infinity;
    previous[node]  = null;
  }

  distances[source] = 0;
  pq.enqueue(source, 0);

  while (pq.size > 0) {
    const { id: current } = pq.dequeue()!;

    // 3. COMMITMENT — skip if already settled
    if (visited.has(current)) continue;
    visited.add(current);

    // 2. RELAXATION — can we offer neighbors a better route?
    for (const { to: neighbor, weight } of graph[current] ?? []) {
      if (visited.has(neighbor)) continue;

      const candidateDistance = distances[current] + weight;

      if (candidateDistance < distances[neighbor]) {
        distances[neighbor] = candidateDistance;
        previous[neighbor]  = current;
        pq.enqueue(neighbor, candidateDistance);  // lazy deletion pattern
      }
    }
  }

  // ── Path reconstruction: walk backwards through 'previous' ──
  function getPath(target: NodeId): NodeId[] {
    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
    }

    // If path doesn't start at source, target is unreachable
    return path[0] === source ? path : [];
  }

  return { distances, previous, getPath };
}

