// ─── Types ────────────────────────────────────────────────────────────────────

interface Edge {
  to: number;
  weight: number;
}

interface ShortestPathResult {
  distances: number[];          // distances[i] = shortest distance from source to i
  predecessors: (number | null)[]; // predecessors[i] = previous node on shortest path
  getPath: (target: number) => number[] | null; // reconstruct path to target
}

// ─── Min-Heap (Priority Queue) ────────────────────────────────────────────────

interface HeapNode {
  node: number;
  distance: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  push(item: HeapNode): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.isEmpty()) return undefined;

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (!this.isEmpty()) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return min;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent].distance <= this.heap[index].distance) break;

      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left  = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left  < length && this.heap[left].distance  < this.heap[smallest].distance) {
        smallest = left;
      }
      if (right < length && this.heap[right].distance < this.heap[smallest].distance) {
        smallest = right;
      }
      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

function dijkstra(
  graph: Edge[][],   // adjacency list: graph[u] = [{to, weight}, ...]
  source: number
): ShortestPathResult {
  const V = graph.length;
  const distances   = new Array<number>(V).fill(Infinity);
  const predecessors = new Array<number | null>(V).fill(null);
  const settled     = new Array<boolean>(V).fill(false);

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push({ node: source, distance: 0 });

  while (!pq.isEmpty()) {
    const { node: u, distance: d } = pq.pop()!;

    // Skip if we've already found a better path (stale entry in heap)
    if (settled[u]) continue;
    settled[u] = true;

    // Early exit: remaining nodes are unreachable or we only need one target
    if (d === Infinity) break;

    for (const { to: v, weight } of graph[u]) {
      if (settled[v]) continue;

      const newDist = distances[u] + weight;

      if (newDist < distances[v]) {
        distances[v]    = newDist;
        predecessors[v] = u;
        pq.push({ node: v, distance: newDist }); // lazy deletion approach
      }
    }
  }

  // Path reconstruction closure
  function getPath(target: number): number[] | null {
    if (distances[target] === Infinity) return null; // unreachable

    const path: number[] = [];
    let current: number | null = target;

    while (current !== null) {
      path.unshift(current);
      current = predecessors[current];
    }

    // Verify path actually starts at source
    return path[0] === source ? path : null;
  }

  return { distances, predecessors, getPath };
}

// ─── Helper: Build Graph ──────────────────────────────────────────────────────

function buildGraph(
  numNodes: number,
  edges: [from: number, to: number, weight: number][],
  directed = false
): Edge[][] {
  const graph: Edge[][] = Array.from({ length: numNodes }, () => []);

  for (const [from, to, weight] of edges) {
    graph[from].push({ to, weight });
    if (!directed) {
      graph[to].push({ to: from, weight });
    }
  }

  return graph;
}

