// ─── Types ────────────────────────────────────────────────────────────────────

interface Edge {
  to: number;
  weight: number;
}

interface ShortestPathResult {
  distances: number[];       // distances[i] = shortest distance from source to node i
  previous: (number | null)[]; // previous[i] = parent node on shortest path to i
}

// ─── Min-Heap Priority Queue ───────────────────────────────────────────────────
// A proper min-heap is critical for O((V+E) log V) performance.

interface HeapNode {
  node: number;
  distance: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  push(item: HeapNode): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;
    const top = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent].distance <= this.heap[i].distance) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left  = 2 * i + 1;
      const right = 2 * i + 2;
      if (left  < n && this.heap[left].distance  < this.heap[smallest].distance) smallest = left;
      if (right < n && this.heap[right].distance < this.heap[smallest].distance) smallest = right;
      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

/**
 * Computes shortest paths from `source` to all nodes in the graph.
 *
 * @param graph   Adjacency list: graph[u] = array of { to, weight } edges
 * @param source  The starting node index
 * @returns       Distances array and previous-node array for path reconstruction
 */
function dijkstra(graph: Edge[][], source: number): ShortestPathResult {
  const n = graph.length;
  const distances = new Array<number>(n).fill(Infinity);
  const previous  = new Array<number | null>(n).fill(null);
  const finalized = new Array<boolean>(n).fill(false);

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push({ node: source, distance: 0 });

  while (pq.size > 0) {
    const { node: u, distance: d } = pq.pop()!;

    // Skip stale entries (a node may appear multiple times in the heap)
    if (finalized[u]) continue;
    finalized[u] = true;

    // No point exploring further — remaining nodes are all farther away
    if (d === Infinity) break;

    for (const { to: v, weight } of graph[u]) {
      if (finalized[v]) continue;

      const newDist = distances[u] + weight;
      if (newDist < distances[v]) {
        distances[v] = newDist;
        previous[v]  = u;
        pq.push({ node: v, distance: newDist });
      }
    }
  }

  return { distances, previous };
}

// ─── Path Reconstruction ──────────────────────────────────────────────────────

/**
 * Reconstructs the actual path from source to target using the `previous` array.
 */
function reconstructPath(
  previous: (number | null)[],
  source: number,
  target: number
): number[] | null {
  const path: number[] = [];
  let current: number | null = target;

  while (current !== null) {
    path.unshift(current);
    if (current === source) return path;
    current = previous[current];
  }

  return null; // target is unreachable
}

