```typescript
type Edge = { to: number; weight: number };
type Graph = Map<number, Edge[]>;

interface DijkstraResult {
  distances: Map<number, number>;
  previous: Map<number, number | null>;
  getPath: (target: number) => number[];
}

// -----------------------------------------------------------
// Min-Heap (Priority Queue) — the engine of efficiency
// Without this, Dijkstra degrades from O((V+E) log V) to O(V²)
// -----------------------------------------------------------
class MinHeap {
  private heap: [number, number][] = []; // [cost, node]

  push(cost: number, node: number): void {
    this.heap.push([cost, node]);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): [number, number] | undefined {
    if (this.heap.length === 0) return undefined;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  get size(): number {
    return this.heap.length;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent][0] <= this.heap[i][0]) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;
      if (left < n && this.heap[left][0] < this.heap[smallest][0]) smallest = left;
      if (right < n && this.heap[right][0] < this.heap[smallest][0]) smallest = right;
      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// -----------------------------------------------------------
// Dijkstra's Algorithm
// -----------------------------------------------------------
function dijkstra(graph: Graph, source: number): DijkstraResult {
  const distances = new Map<number, number>();
  const previous = new Map<number, number | null>();
  const settled = new Set<number>();
  const pq = new MinHeap();

  // Initialize all known nodes to infinity
  for (const node of graph.keys()) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }

  // The source costs nothing to reach
  distances.set(source, 0);
  pq.push(0, source);

  while (pq.size > 0) {
    const [currentCost, current] = pq.pop()!;

    // Skip if we've already found the optimal path to this node
    // (stale entries linger in the heap after relaxation)
    if (settled.has(current)) continue;
    settled.add(current);

    const neighbors = graph.get(current) ?? [];
    for (const { to, weight } of neighbors) {
      if (settled.has(to)) continue;

      // Relaxation: is this path cheaper than what we know?
      const candidate = currentCost + weight;
      if (candidate < (distances.get(to) ?? Infinity)) {
        distances.set(to, candidate);
        previous.set(to, current);
        pq.push(candidate, to); // Push updated cost (old entry becomes stale)
      }
    }
  }

  // Reconstruct path by walking backwards through 'previous'
  const getPath = (target: number): number[] => {
    const path: number[] = [];
    let current: number | null | undefined = target;
    while (current != null) {
      path.unshift(current);
      current = previous.get(current);
    }
    // Return empty if no valid path exists
    return path[0] === source ? path : [];
  };

  return { distances, previous, getPath };
}

// -----------------------------------------------------------
// Helper: build an undirected weighted graph
// -----------------------------------------------------------
function buildGraph(edges: [number, number, number][]): Graph {
  const graph: Graph = new Map();
  for (const [u, v, w] of edges) {
    if (!graph.has(u)) graph.set(u, []);
    if (!graph.has(v)) graph.set(v, []);
    graph.get(u)!.push({ to: v, weight: w });
    graph.get(v)!.push({ to: u, weight: w }); // Remove for directed graph
  }
  return graph;
}

