// ─────────────────────────────────────────────
//  Min-Heap (Priority Queue)
//  Stores [priority, value] pairs
// ─────────────────────────────────────────────

class MinHeap<T> {
  private heap: [number, T][] = [];

  get size(): number {
    return this.heap.length;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  /** Insert a value with an associated priority */
  push(priority: number, value: T): void {
    this.heap.push([priority, value]);
    this._bubbleUp(this.heap.length - 1);
  }

  /** Remove and return the item with the lowest priority */
  pop(): [number, T] | null {
    if (this.isEmpty()) return null;

    const top = this.heap[0];
    const last = this.heap.pop()!;

    if (!this.isEmpty()) {
      this.heap[0] = last;
      this._sinkDown(0);
    }

    return top;
  }

  private _bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent][0] <= this.heap[index][0]) break;
      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private _sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left  = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left  < length && this.heap[left][0]  < this.heap[smallest][0]) smallest = left;
      if (right < length && this.heap[right][0] < this.heap[smallest][0]) smallest = right;

      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

