class Graph {
  private adjacency: Map<number, Edge[]>;
  readonly nodeCount: number;

  constructor(nodeCount: number) {
    this.nodeCount = nodeCount;
    this.adjacency = new Map();

    for (let i = 0; i < nodeCount; i++) {
      this.adjacency.set(i, []);
    }
  }

  /**
   * Add a directed edge u → v with given weight.
   * Call twice (u→v, v→u) for undirected graphs.
   */
  addEdge(from: number, to: number, weight: number): void {
    if (weight < 0) throw new Error("Dijkstra requires non-negative edge weights.");
    this._validateNode(from);
    this._validateNode(to);
    this.adjacency.get(from)!.push({ to, weight });
  }

  /** Convenience: add an undirected edge */
  addUndirectedEdge(u: number, v: number, weight: number): void {
    this.addEdge(u, v, weight);
    this.addEdge(v, u, weight);
  }

  getNeighbors(node: number): Edge[] {
    return this.adjacency.get(node) ?? [];
  }

  private _validateNode(node: number): void {
    if (node < 0 || node >= this.nodeCount) {
      throw new RangeError(`Node ${node} is out of range [0, ${this.nodeCount - 1}]`);
    }
  }
}

