// Minimal binary min-heap over [priority, value] pairs
class MinHeap<T> {
  private data: [number, T][] = [];

  push(priority: number, value: T) {
    this.data.push([priority, value]);
    this.bubbleUp(this.data.length - 1);
  }

  pop(): [number, T] | undefined {
    if (this.data.length === 0) return undefined;
    const top = this.data[0];
    const last = this.data.pop()!;
    if (this.data.length > 0) {
      this.data[0] = last;
      this.sinkDown(0);
    }
    return top;
  }

  get size() { return this.data.length; }

  private bubbleUp(i: number) {
    while (i > 0) {
      const parent = (i - 1) >> 1;
      if (this.data[parent][0] <= this.data[i][0]) break;
      [this.data[parent], this.data[i]] = [this.data[i], this.data[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number) {
    const n = this.data.length;
    while (true) {
      let smallest = i;
      const l = 2 * i + 1, r = 2 * i + 2;
      if (l < n && this.data[l][0] < this.data[smallest][0]) smallest = l;
      if (r < n && this.data[r][0] < this.data[smallest][0]) smallest = r;
      if (smallest === i) break;
      [this.data[smallest], this.data[i]] = [this.data[i], this.data[smallest]];
      i = smallest;
    }
  }
}

/**
 * Returns shortest distances from `source` to every node,
 * and the `previous` array for path reconstruction.
 * Graph is adjacency list indexed 0..n-1.
 */
function dijkstra(
  graph: Graph,
  source: number,
): { distances: number[]; previous: number[] } {
  const n = graph.length;
  const distances = new Array<number>(n).fill(Infinity);
  const previous = new Array<number>(n).fill(-1);
  const settled = new Uint8Array(n);

  distances[source] = 0;
  const heap = new MinHeap<number>();
  heap.push(0, source);

  while (heap.size > 0) {
    const [dist, u] = heap.pop()!;
    if (settled[u]) continue; // stale entry
    settled[u] = 1;

    for (const { to: v, weight } of graph[u]) {
      const candidate = dist + weight;
      if (candidate < distances[v]) {
        distances[v] = candidate;
        previous[v] = u;
        heap.push(candidate, v);
      }
    }
  }

  return { distances, previous };
}

/** Reconstructs path from source to target using the `previous` array. */
function reconstructPath(previous: number[], target: number): number[] {
  const path: number[] = [];
  for (let node = target; node !== -1; node = previous[node]) {
    path.unshift(node);
  }
  return path;
}

