  const prev: (number | null)[] = Array(nodeCount).fill(null);
  const settled = new Set<number>();

  dist[source] = 0;

  // Min-heap: [distance, node]
  const heap: [number, number][] = [[0, source]];

  const heapPush = (d: number, n: number) => {
    heap.push([d, n]);
