    const [d, u] = heapPop();
    if (settled.has(u)) continue; // stale entry
    settled.add(u);

    for (const { to: v, weight } of graph.get(u) ?? []) {
      const candidate = d + weight;
      if (candidate < dist[v]) {
        dist[v] = candidate;
        prev[v] = u;
        heapPush(candidate, v);
      }
    }
  }

