  A: [{ to: "B", weight: 4 }, { to: "C", weight: 2 }],
  B: [{ to: "C", weight: 5 }, { to: "D", weight: 10 }],
  C: [{ to: "E", weight: 3 }],
  D: [{ to: "F", weight: 11 }],
  E: [{ to: "D", weight: 4 }],
  F: [],
};

const { distances, getPath } = dijkstra(cityMap, "A");

console.log("Shortest distances from A:");
console.log(distances);
// { A: 0, B: 4, C: 2, D: 9, E: 5, F: 20 }

console.log("\nShortest path A → F:", getPath("F").join(" → "));
// A → C → E → D → F

console.log("Shortest path A → B:", getPath("B").join(" → "));
// A → B
```

