// ─── Types ────────────────────────────────────────────────────────────────────

interface Edge {
  to: number;
  weight: number;
}

interface DijkstraResult {
  distances: number[];       // shortest distance from source to each node
  previous: (number | null)[]; // predecessor of each node on shortest path
}

// ─── Min-Heap (Priority Queue) ────────────────────────────────────────────────

interface HeapNode {
  node: number;
  distance: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  push(item: HeapNode): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;

    const min = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }

    return min;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent].distance <= this.heap[index].distance) break;
      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const left  = 2 * index + 1;
      const right = 2 * index + 2;
      let smallest = index;

      if (left  < length && this.heap[left].distance  < this.heap[smallest].distance) smallest = left;
      if (right < length && this.heap[right].distance < this.heap[smallest].distance) smallest = right;

      if (smallest === index) break;

      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

/**
 * Finds the shortest paths from `source` to all other nodes.
 * @param graph  Adjacency list: graph[u] = [{ to: v, weight: w }, ...]
 * @param source Starting node index
 */
function dijkstra(graph: Edge[][], source: number): DijkstraResult {
  const numNodes = graph.length;
  const distances = new Array<number>(numNodes).fill(Infinity);
  const previous  = new Array<number | null>(numNodes).fill(null);
  const visited   = new Array<boolean>(numNodes).fill(false);

  distances[source] = 0;

  const pq = new MinHeap();
  pq.push({ node: source, distance: 0 });

  while (!pq.isEmpty()) {
    const { node: u, distance: d } = pq.pop()!;

    // Skip if we already found a better path (stale entry in heap)
    if (visited[u]) continue;
    visited[u] = true;

    // No point exploring further — all remaining entries are farther
    if (d > distances[u]) continue;

    for (const edge of graph[u]) {
      const { to: v, weight } = edge;

      if (visited[v]) continue;

      const newDist = distances[u] + weight;

      if (newDist < distances[v]) {
        distances[v] = newDist;
        previous[v]  = u;
        pq.push({ node: v, distance: newDist });
      }
    }
  }

  return { distances, previous };
}

// ─── Path Reconstruction ──────────────────────────────────────────────────────

/**
 * Reconstructs the shortest path from source to target.
 * Returns an empty array if no path exists.
 */
function reconstructPath(
  previous: (number | null)[],
  source: number,
  target: number
): number[] {
  const path: number[] = [];
  let current: number | null = target;

  while (current !== null) {
    path.unshift(current);
    if (current === source) break;
    current = previous[current];
  }

  // Return empty array if no valid path was found
  return path[0] === source ? path : [];
}

