function buildGraph(numNodes: number, edges: [number, number, number][]): Edge[][] {
  const graph: Edge[][] = Array.from({ length: numNodes }, () => []);
  for (const [u, v, w] of edges) {
    graph[u].push({ to: v, weight: w });
    graph[v].push({ to: u, weight: w }); // undirected
  }
  return graph;
}

