// ─── Types ───────────────────────────────────────────────────────────────────

interface Edge {
  to: string;
  weight: number;
}

interface Graph {
  [node: string]: Edge[];
}

interface DijkstraResult {
  distances: Record<string, number>;
  previous: Record<string, string | null>;
  getPath: (target: string) => string[];
}

// ─── Min-Heap Priority Queue ──────────────────────────────────────────────────

interface HeapNode {
  node: string;
  cost: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  push(item: HeapNode): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent].cost <= this.heap[i].cost) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private sinkDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;
      if (left < n && this.heap[left].cost < this.heap[smallest].cost)
        smallest = left;
      if (right < n && this.heap[right].cost < this.heap[smallest].cost)
        smallest = right;
      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

function dijkstra(graph: Graph, source: string): DijkstraResult {
  const distances: Record<string, number> = {};
  const previous: Record<string, string | null> = {};
  const visited = new Set<string>();
  const pq = new MinHeap();

  // Initialize — every node is infinitely far away except the source
  for (const node in graph) {
    distances[node] = Infinity;
    previous[node] = null;
  }
  distances[source] = 0;
  pq.push({ node: source, cost: 0 });

  while (pq.size > 0) {
    const { node, cost } = pq.pop()!;

    // Skip stale entries — the heap may contain outdated costs
    if (visited.has(node)) continue;
    visited.add(node);

    // Crystallize: if we can't improve from here, neighbors are already optimal
    if (cost > distances[node]) continue;

    for (const { to, weight } of graph[node] ?? []) {
      if (visited.has(to)) continue;

      const newCost = distances[node] + weight;

      if (newCost < distances[to]) {
        distances[to] = newCost;
        previous[to] = node;
        pq.push({ node: to, cost: newCost });
      }
    }
  }

  // Reconstruct the path by following breadcrumbs backward
  function getPath(target: string): string[] {
    const path: string[] = [];
    let current: string | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
      // Guard against disconnected nodes
      if (current !== null && !(current in previous)) break;
    }

    return path[0] === source ? path : []; // Empty if unreachable
  }

  return { distances, previous, getPath };
}

