function dijkstra(graph: Graph, source: NodeId): DijkstraResult {
  const distances = new Map<NodeId, number>();
  const previous  = new Map<NodeId, NodeId | null>();
  const visited   = new Set<NodeId>();
  const pq        = new MinHeap();

  // Step 1: Initialize all distances to Infinity
  for (const node of Object.keys(graph)) {
    distances.set(node, Infinity);
    previous.set(node, null);
  }

  // Step 2: Source node has distance 0
  distances.set(source, 0);
  pq.push({ id: source, priority: 0 });

  // Step 3: Process nodes in order of increasing distance
  while (!pq.isEmpty()) {
    const current = pq.pop()!;
    const { id: u, priority: distU } = current;

    // Skip if we already found a shorter path to this node
    // (stale entry in the priority queue)
    if (visited.has(u)) continue;
    visited.add(u);

    // Early termination optimization: all remaining nodes are farther
    if (distU === Infinity) break;

    // Step 4: Relax neighbors
    const neighbors = graph[u] ?? [];
    for (const { to: v, weight } of neighbors) {
      if (visited.has(v)) continue;

      const candidate = distances.get(u)! + weight;

      if (candidate < (distances.get(v) ?? Infinity)) {
        distances.set(v, candidate);
        previous.set(v, u);
        // Push new entry; stale old entry will be skipped via visited check
        pq.push({ id: v, priority: candidate });
      }
    }
  }

  // ── Path reconstruction helper ──────────────────────────
  function getPath(target: NodeId): NodeId[] | null {
    if (!distances.has(target) || distances.get(target) === Infinity) {
      return null; // No path exists
    }

    const path: NodeId[] = [];
    let current: NodeId | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous.get(current) ?? null;
    }

    // Verify the path actually starts at source
    return path[0] === source ? path : null;
  }

  function getDistance(target: NodeId): number {
    return distances.get(target) ?? Infinity;
  }

  return { distances, previous, getPath, getDistance };
}

