): DijkstraResult {
  const V = graph.length;
  const distances = new Array<number>(V).fill(Infinity);
  const previous  = new Array<number | null>(V).fill(null);
  const visited   = new Array<boolean>(V).fill(false);

  distances[source] = 0;

  const pq = new MinPriorityQueue();
  pq.enqueue(source, 0);

  while (!pq.isEmpty()) {
    const { node: u, distance: distU } = pq.dequeue();

    // Stale entry — a shorter path was already found
    if (visited[u]) continue;
    visited[u] = true;

    // Early termination possible here if targeting a single destination

    for (const { to: v, weight } of graph[u]) {
      if (visited[v]) continue;

      const newDist = distU + weight;

      if (newDist < distances[v]) {
        distances[v] = newDist;
        previous[v]  = u;
        pq.enqueue(v, newDist);  // lazy deletion: old entry becomes stale
      }
    }
  }

  return { distances, previous };
}

// ─── Path Reconstruction ──────────────────────────────────────────────────────

function reconstructPath(
  previous: (number | null)[],
  source: number,
  target: number
): number[] | null {
  const path: number[] = [];
  let current: number | null = target;

  while (current !== null) {
    path.unshift(current);
    if (current === source) return path;
    current = previous[current];
  }

  return null; // target is unreachable
}

// ─── Graph Builder Helper ─────────────────────────────────────────────────────

function buildGraph(
  vertices: number,
  edges: [number, number, number][], // [from, to, weight]
  directed = false
): Edge[][] {
  const graph: Edge[][] = Array.from({ length: vertices }, () => []);

  for (const [from, to, weight] of edges) {
    graph[from].push({ to, weight });
    if (!directed) {
      graph[to].push({ to: from, weight });
    }
  }

  return graph;
}

