// ─── Types ────────────────────────────────────────────────────────────────────

interface Edge {
  to: number;
  weight: number;
}

interface DijkstraResult {
  distances: number[];
  previous: (number | null)[];
  getShortestPath: (target: number) => number[] | null;
}

// ─── Min-Heap (Priority Queue) ────────────────────────────────────────────────

interface HeapNode {
  node: number;
  distance: number;
}

class MinHeap {
  private heap: HeapNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  push(item: HeapNode): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;
    const min = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.sinkDown(0);
    }
    return min;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[parent].distance <= this.heap[index].distance) break;
      [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
      index = parent;
    }
  }

  private sinkDown(index: number): void {
    const length = this.heap.length;
    while (true) {
      let smallest = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;

      if (left < length && this.heap[left].distance < this.heap[smallest].distance)
        smallest = left;
      if (right < length && this.heap[right].distance < this.heap[smallest].distance)
        smallest = right;

      if (smallest === index) break;
      [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
      index = smallest;
    }
  }
}

// ─── Dijkstra's Algorithm ─────────────────────────────────────────────────────

function dijkstra(graph: Edge[][], source: number): DijkstraResult {
  const numNodes = graph.length;
  const distances = new Array<number>(numNodes).fill(Infinity);
  const previous = new Array<number | null>(numNodes).fill(null);
  const visited = new Set<number>();
  const pq = new MinHeap();

  distances[source] = 0;
  pq.push({ node: source, distance: 0 });

  while (pq.size > 0) {
    const { node: current, distance: currentDist } = pq.pop()!;

    // Skip stale entries (node was already settled with a shorter path)
    if (visited.has(current)) continue;
    visited.add(current);

    // Early exit: remaining nodes are unreachable or no shorter paths exist
    if (currentDist === Infinity) break;

    for (const { to, weight } of graph[current]) {
      if (visited.has(to)) continue;

      const newDist = distances[current] + weight;
      if (newDist < distances[to]) {
        distances[to] = newDist;
        previous[to] = current;
        pq.push({ node: to, distance: newDist });
      }
    }
  }

  // Reconstruct shortest path to a target node
  function getShortestPath(target: number): number[] | null {
    if (distances[target] === Infinity) return null; // unreachable

    const path: number[] = [];
    let current: number | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current];
    }

    // Verify path actually starts at source
    return path[0] === source ? path : null;
  }

  return { distances, previous, getShortestPath };
}

