function dijkstra(graph: Graph, source: string): DijkstraResult {
  const distances: Record<string, number> = {};
  const previous: Record<string, string | null> = {};
  const visited = new Set<string>();
  const pq = new MinHeap();

  // Initialize all distances to Infinity
  for (const node in graph) {
    distances[node] = Infinity;
    previous[node] = null;
  }

  // Source node starts at distance 0
  distances[source] = 0;
  pq.push(0, source);

  while (pq.size > 0) {
    const entry = pq.pop();
    if (!entry) break;

    const [currentDist, currentNode] = entry;

    // Skip if already visited (stale entry in heap)
    if (visited.has(currentNode)) continue;
    visited.add(currentNode);

    // Explore neighbors
    const neighbors = graph[currentNode] || [];
    for (const { to, weight } of neighbors) {
      if (visited.has(to)) continue;

      const newDist = currentDist + weight;

      if (newDist < distances[to]) {
        distances[to] = newDist;
        previous[to] = currentNode;
        pq.push(newDist, to);
      }
    }
  }

  // Path reconstruction helper
  function getShortestPath(target: string): string[] {
    const path: string[] = [];
    let current: string | null = target;

    while (current !== null) {
      path.unshift(current);
      current = previous[current] ?? null;
    }

    // If the first node isn't the source, no path exists
    return path[0] === source ? path : [];
  }

  return { distances, previous, getShortestPath };
}

