      const newDist = (distances.get(currentNode) ?? Infinity) + weight;
      const oldDist = distances.get(neighbor) ?? Infinity;

      if (newDist < oldDist) {
        distances.set(neighbor, newDist);
        previous.set(neighbor, currentNode);
        pq.push(neighbor, newDist); // Push updated priority (lazy deletion)
      }
    }
  }

