  function getPath(target: string): string[] {
    const path: string[] = [];
    let current: string | null | undefined = target;

    while (current !== null && current !== undefined) {
      path.unshift(current);
      current = previous.get(current);
    }

    // If the path doesn't start at source, no path exists
    if (path[0] !== source) return [];

    return path;
  }

  return { distances, previous, getPath };
}

