# LRU Cache Implementation in TypeScript

## Data Structure Choice

The key insight is combining two structures:
- **HashMap** → O(1) key lookup
- **Doubly Linked List** → O(1) node removal/insertion (with direct node reference)

A singly linked list would require O(n) traversal to find previous nodes. Arrays would require O(n) shifts. Together, these give us O(1) for both operations.

```typescript
/**
 * Node in our doubly linked list
 * Stores both key (for HashMap cleanup) and value
 */
class DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null = null;
  next: DLinkedNode<T> | null = null;

  constructor(key: string = "", value: T = undefined as T) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations
 *
 * Mental model: imagine a queue where:
 * - HEAD.next  → Most Recently Used (MRU)
 * - TAIL.prev  → Least Recently Used (LRU)
 *
 * HEAD ↔ [MRU] ↔ [...] ↔ [LRU] ↔ TAIL
 */
class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, DLinkedNode<T>>;
  private head: DLinkedNode<T>; // Sentinel: MRU boundary
  private tail: DLinkedNode<T>; // Sentinel: LRU boundary

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new Error(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Sentinel nodes eliminate null checks on every operation
    this.head = new DLinkedNode<T>("HEAD");
    this.tail = new DLinkedNode<T>("TAIL");
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ───────────────────────────────────────────────────────────

  /**
   * O(1) - Returns value or undefined if not found
   * Side effect: marks key as most recently used
   */
  get(key: string): T | undefined {
    const node = this.cache.get(key);

    if (!node) return undefined;

    // Promote to MRU position
    this.moveToFront(node);
    return node.value;
  }

  /**
   * O(1) - Inserts or updates a key-value pair
   * Evicts LRU entry if over capacity
   */
  put(key: string, value: T): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update value and promote to MRU
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU before adding if at capacity
    if (this.cache.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new DLinkedNode<T>(key, value);
    this.addToFront(newNode);
    this.cache.set(key, newNode);
  }

  /**
   * Remove a specific key from cache
   */
  delete(key: string): boolean {
    const node = this.cache.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.cache.delete(key);
    return true;
  }

  /**
   * Peek at a value WITHOUT updating recency
   * Useful for read-only inspection
   */
  peek(key: string): T | undefined {
    return this.cache.get(key)?.value;
  }

  /** Reset to empty state */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get size(): number {
    return this.cache.size;
  }

  /**
   * Debug: returns keys from MRU → LRU order
   */
  toOrderedKeys(): string[] {
    const keys: string[] = [];
    let current = this.head.next;

    while (current && current !== this.tail) {
      keys.push(current.key);
      current = current.next;
    }

    return keys;
  }

  // ─── Private Helpers ──────────────────────────────────────────────────────

  /**
   * Insert node immediately after HEAD (MRU position)
   *
   * Before: HEAD ↔ [first] ↔ ...
   * After:  HEAD ↔ [node] ↔ [first] ↔ ...
   */
  private addToFront(node: DLinkedNode<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Detach node from its current position
   * Relies on sentinel nodes — no null checks needed
   *
   * Before: [prev] ↔ [node] ↔ [next]
   * After:  [prev] ↔ [next]   (node is now floating)
   */
  private removeNode(node: DLinkedNode<T>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Clear pointers to help GC
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DLinkedNode<T>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /**
   * Remove the LRU node (just before TAIL) from both
   * the linked list and the HashMap
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev;

    // Guard against evicting sentinels (empty cache edge case)
    if (!lruNode || lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key);
  }
}
