## Data Structure Choice

An LRU cache requires **O(1) for both get and put**, which demands two complementary structures:

| Structure | Purpose | Why |
|-----------|---------|-----|
| **HashMap** (`Map<K, Node>`) | Key → Node lookup | O(1) access by key |
| **Doubly Linked List** | Tracks recency order | O(1) insert/delete anywhere with node reference |

Using both together: the HashMap gives us the node pointer directly, and the doubly linked list lets us reorder/evict in O(1) without searching.

---

```typescript
// ============================================================
// Node definition for the doubly linked list
// ============================================================
class DLLNode<K, V> {
  key: K;
  value: V;
  prev: DLLNode<K, V> | null = null;
  next: DLLNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

// ============================================================
// LRU Cache
// ============================================================
class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, DLLNode<K, V>>;

  // Sentinel nodes: head = least-recently-used, tail = most-recently-used
  // Using sentinels eliminates null-checks at list boundaries
  private readonly head: DLLNode<K, V>; // dummy LRU end
  private readonly tail: DLLNode<K, V>; // dummy MRU end

  /**
   * @param capacity - Maximum number of entries. Must be a positive integer.
   * @throws {RangeError} If capacity is not a positive integer.
   */
  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes (key/value are placeholders)
    this.head = new DLLNode<K, V>(null as unknown as K, null as unknown as V);
    this.tail = new DLLNode<K, V>(null as unknown as K, null as unknown as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ──────────────────────────────────────────────────────────
  // Public API
  // ──────────────────────────────────────────────────────────

  /**
   * Retrieve a value by key.
   * Marks the entry as most-recently-used.
   *
   * @returns The cached value, or `undefined` if not found.
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);

    if (!node) return undefined;

    // Promote to MRU position
    this.moveToTail(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * If at capacity, evicts the least-recently-used entry first.
   *
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value in-place and promote to MRU
      existing.value = value;
      this.moveToTail(existing);
      return;
    }

    // Evict LRU entry if at capacity
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    const newNode = new DLLNode(key, value);
    this.map.set(key, newNode);
    this.insertAtTail(newNode); // newest entry = MRU
  }

  /**
   * Remove a specific key from the cache.
   *
   * @returns `true` if the key existed, `false` otherwise.
   * Time: O(1) | Space: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Remove all entries. Time: O(n) */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /** Current number of cached entries. */
  get size(): number {
    return this.map.size;
  }

  /** Check if a key exists without affecting recency order. */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /**
   * Returns entries from LRU → MRU order (oldest first).
   * Useful for debugging and testing.
   */
  toArray(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push([current!.key, current!.value]);
      current = current!.next;
    }

    return result;
  }

  // ──────────────────────────────────────────────────────────
  // Private helpers — all O(1)
  // ──────────────────────────────────────────────────────────

  /** Insert node immediately before the tail sentinel (MRU position). */
  private insertAtTail(node: DLLNode<K, V>): void {
    const prev = this.tail.prev!;
    prev.next = node;
    node.prev = prev;
    node.next = this.tail;
    this.tail.prev = node;
  }

  /** Unlink a node from its current position in the list. */
  private removeNode(node: DLLNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Null out pointers to help GC
    node.prev = null;
    node.next = null;
  }

  /** Move an existing node to the MRU (tail) position. */
  private moveToTail(node: DLLNode<K, V>): void {
    this.removeNode(node);
    this.insertAtTail(node);
  }

  /**
   * Evict the least-recently-used entry (node after head sentinel).
   * The node's key is stored on the node itself so we can delete it
   * from the map without a separate reverse lookup.
   */
  private evictLRU(): void {
    const lru = this.head.next!;
    // Guard: should never evict sentinel, but safety-first
    if (lru === this.tail) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}
