  private readonly cache: Map<K, DLinkedNode<K, V>>;

  // Sentinel nodes eliminate null checks on every operation
  // head.next  → Most Recently Used (MRU)
  // tail.prev  → Least Recently Used (LRU)
  private readonly head: DLinkedNode<K, V>; // dummy MRU sentinel
  private readonly tail: DLinkedNode<K, V>; // dummy LRU sentinel

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Wire up sentinels — the list is always "bookended" by these
    this.head = new DLinkedNode<K, V>();
    this.tail = new DLinkedNode<K, V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Public API ─────────────────────────────────────────────────────────────

  /**
   * Returns the value for `key`, or -1 if not present.
   * Marks the entry as most-recently used.
   * O(1) time.
   */
  get(key: K): V | -1 {
    const node = this.cache.get(key);
    if (!node) return -1;

    this.moveToFront(node);
    return node.value as V;
  }

  /**
   * Inserts or updates `key` with `value`.
   * Evicts the least-recently-used entry when over capacity.
   * O(1) time.
   */
  put(key: K, value: V): void {
    const existing = this.cache.get(key);

    if (existing) {
      // Update value in-place, then promote to MRU position
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const newNode = new DLinkedNode(key, value);
    this.cache.set(key, newNode);
    this.insertAtFront(newNode);

    if (this.cache.size > this.capacity) {
      this.evictLRU();
    }
  }

  /** Number of entries currently stored. */
  get size(): number {
    return this.cache.size;
  }

