# LRU Cache Implementation in TypeScript

## Data Structure Choice

The optimal implementation uses a **combination of**:
- **HashMap** (`Map<number, Node>`): Provides O(1) key lookup
- **Doubly Linked List**: Provides O(1) insertion and deletion at any position

This combination achieves O(1) for both `get` and `put` operations. A singly linked list would require O(n) deletion since we can't access the previous node.

---

## Complete Implementation

```typescript
/**
 * Doubly Linked List Node
 */
class DLLNode {
  key: number;
  value: number;
  prev: DLLNode | null = null;
  next: DLLNode | null = null;

  constructor(key: number, value: number) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache Implementation
 * - Uses a HashMap for O(1) lookups
 * - Uses a Doubly Linked List to track usage order
 * - Most recently used items are at the HEAD (after sentinel)
 * - Least recently used items are at the TAIL (before sentinel)
 */
class LRUCache {
  private capacity: number;
  private cache: Map<number, DLLNode>;
  private head: DLLNode; // Sentinel head (MRU side)
  private tail: DLLNode; // Sentinel tail (LRU side)

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("Capacity must be a positive integer");
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Initialize sentinel nodes to avoid null checks
    this.head = new DLLNode(0, 0); // Dummy head
    this.tail = new DLLNode(0, 0); // Dummy tail
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Get the value of a key if it exists in the cache.
   * Moves the accessed node to the front (most recently used).
   * @returns value if found, -1 otherwise
   * Time Complexity: O(1)
   */
  get(key: number): number {
    const node = this.cache.get(key);

    if (!node) {
      return -1; // Cache miss
    }

    // Move to front (mark as most recently used)
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair in the cache.
   * If capacity is exceeded, evicts the least recently used item.
   * Time Complexity: O(1)
   */
  put(key: number, value: number): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update existing node's value and move to front
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Create new node
    const newNode = new DLLNode(key, value);

    // Add to cache map and front of list
    this.cache.set(key, newNode);
    this.addToFront(newNode);

    // Evict LRU if over capacity
    if (this.cache.size > this.capacity) {
      this.evictLRU();
    }
  }

  /**
   * Returns the current number of items in the cache.
   */
  get size(): number {
    return this.cache.size;
  }

  /**
   * Check if a key exists in the cache WITHOUT updating usage order.
   * Useful for peek operations.
   */
  has(key: number): boolean {
    return this.cache.has(key);
  }

  /**
   * Clear all entries from the cache.
   */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Private Helper Methods ───────────────────────────────────────────────

  /**
   * Add a node right after the sentinel head (most recently used position).
   */
  private addToFront(node: DLLNode): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Remove a node from the doubly linked list.
   */
  private removeNode(node: DLLNode): void {
    const prevNode = node.prev!;
    const nextNode = node.next!;
    prevNode.next = nextNode;
    nextNode.prev = prevNode;
  }

  /**
   * Move an existing node to the front of the list (mark as MRU).
   */
  private moveToFront(node: DLLNode): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /**
   * Remove the node just before the sentinel tail (LRU node) and
   * delete it from the cache map.
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: don't remove sentinel head (empty cache edge case)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key);
  }

  /**
   * Debug utility: returns all keys from MRU → LRU order.
   */
  getOrderedKeys(): number[] {
    const keys: number[] = [];
    let current = this.head.next;

    while (current && current !== this.tail) {
      keys.push(current.key);
      current = current.next;
    }

    return keys;
  }
}
