## Data Structure Choice Explanation

The optimal approach uses a **combination of two data structures**:

1. **HashMap (Map)** — Provides O(1) key lookup to find nodes in the cache
2. **Doubly Linked List** — Maintains access order with O(1) insertion and deletion (no shifting like arrays)

**Why a Doubly Linked List?**
- We need to move nodes to the "most recently used" position in O(1) time
- We need to remove the "least recently used" node (tail) in O(1) time
- Doubly linked nodes allow us to splice out any node without traversal

---

## Complete TypeScript Implementation

```typescript
// ============================================================
// Node for the Doubly Linked List
// ============================================================
class DLinkedNode<K, V> {
  key: K | null;
  value: V | null;
  prev: DLinkedNode<K, V> | null;
  next: DLinkedNode<K, V> | null;

  constructor(key: K | null = null, value: V | null = null) {
    this.key = key;
    this.value = value;
    this.prev = null;
    this.next = null;
  }
}

// ============================================================
// LRU Cache Implementation
// ============================================================
class LRUCache<K, V> {
  private capacity: number;
  private size: number;
  private cache: Map<K, DLinkedNode<K, V>>;

  // Sentinel nodes: head = most recently used side, tail = least recently used side
  private head: DLinkedNode<K, V>; // dummy head
  private tail: DLinkedNode<K, V>; // dummy tail

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("LRU Cache capacity must be a positive integer.");
    }

    this.capacity = Math.floor(capacity); // Guard against float capacities
    this.size = 0;
    this.cache = new Map<K, DLinkedNode<K, V>>();

    // Initialize dummy head and tail to simplify edge cases
    this.head = new DLinkedNode<K, V>();
    this.tail = new DLinkedNode<K, V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // -------------------------------------------------------
  // GET: Retrieve value by key — O(1)
  // Returns the value if found, or -1 (undefined) if not
  // -------------------------------------------------------
  get(key: K): V | -1 {
    const node = this.cache.get(key);

    if (!node) {
      return -1; // Cache miss
    }

    // Move accessed node to the front (most recently used)
    this.moveToHead(node);
    return node.value as V;
  }

  // -------------------------------------------------------
  // PUT: Insert or update a key-value pair — O(1)
  // Evicts the LRU item if capacity is exceeded
  // -------------------------------------------------------
  put(key: K, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Key exists: update value and move to head
      existingNode.value = value;
      this.moveToHead(existingNode);
    } else {
      // Key doesn't exist: create new node
      const newNode = new DLinkedNode<K, V>(key, value);
      this.cache.set(key, newNode);
      this.addToHead(newNode);
      this.size++;

      // Evict the least recently used item if over capacity
      if (this.size > this.capacity) {
        const lruNode = this.removeTail();
        if (lruNode && lruNode.key !== null) {
          this.cache.delete(lruNode.key);
        }
        this.size--;
      }
    }
  }

  // -------------------------------------------------------
  // DELETE: Manually remove a key from the cache — O(1)
  // -------------------------------------------------------
  delete(key: K): boolean {
    const node = this.cache.get(key);

    if (!node) {
      return false; // Key not found
    }

    this.removeNode(node);
    this.cache.delete(key);
    this.size--;
    return true;
  }

  // -------------------------------------------------------
  // PEEK: Get value WITHOUT updating access order — O(1)
  // -------------------------------------------------------
  peek(key: K): V | -1 {
    const node = this.cache.get(key);
    return node ? (node.value as V) : -1;
  }

  // -------------------------------------------------------
  // HAS: Check if a key exists WITHOUT updating order — O(1)
  // -------------------------------------------------------
  has(key: K): boolean {
    return this.cache.has(key);
  }

  // -------------------------------------------------------
  // CLEAR: Reset the entire cache
  // -------------------------------------------------------
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  // -------------------------------------------------------
  // GETSIZE: Returns the current number of items
  // -------------------------------------------------------
  getSize(): number {
    return this.size;
  }

  // -------------------------------------------------------
  // KEYS: Returns all keys from MRU to LRU order
  // -------------------------------------------------------
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      if (current && current.key !== null) {
        result.push(current.key);
      }
      current = current?.next ?? this.tail;
    }

    return result;
  }

  // -------------------------------------------------------
  // TOSTRING: Visual representation for debugging
  // -------------------------------------------------------
  toString(): string {
    const keys = this.keys();
    return `LRUCache(capacity=${this.capacity}, size=${this.size}) [MRU → LRU]: ${keys.join(" → ")}`;
  }

  // ===========================================================
  // Private Helper Methods (Doubly Linked List Operations)
  // ===========================================================

  /**
   * Add a node right after the dummy head (most recently used position)
   */
  private addToHead(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;

    if (this.head.next) {
      this.head.next.prev = node;
    }

    this.head.next = node;
  }

  /**
   * Remove a node from its current position in the list
   */
  private removeNode(node: DLinkedNode<K, V>): void {
    if (node.prev) {
      node.prev.next = node.next;
    }
    if (node.next) {
      node.next.prev = node.prev;
    }
    // Nullify pointers to prevent memory leaks
    node.prev = null;
    node.next = null;
  }

  /**
   * Move an existing node to the head (mark as most recently used)
   */
  private moveToHead(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToHead(node);
  }

  /**
   * Remove the node just before the dummy tail (least recently used)
   * Returns the removed node so its key can be deleted from the map
   */
  private removeTail(): DLinkedNode<K, V> | null {
    const lruNode = this.tail.prev;

    // Safety check: don't remove dummy head
    if (!lruNode || lruNode === this.head) {
      return null;
    }

    this.removeNode(lruNode);
    return lruNode;
  }
}

