### Implementation

```typescript
class LRUNode {
  constructor(
    public key: number,
    public value: number,
    public prev: LRUNode | null = null,
    public next: LRUNode | null = null
  ) {}
}

class LRUCache {
  private capacity: number;
  private map: Map<number, LRUNode>;
  private head: LRUNode; // sentinel — most-recent side
  private tail: LRUNode; // sentinel — least-recent side

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got ${capacity}`);
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinels — never hold real data
    this.head = new LRUNode(-1, -1);
    this.tail = new LRUNode(-1, -1);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // O(1)
  get(key: number): number {
    const node = this.map.get(key);
    if (!node) return -1; // cache miss

    this._remove(node);
    this._insertAtFront(node); // mark as most-recently-used
    return node.value;
  }

  // O(1)
  put(key: number, value: number): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value and promote to front
      existing.value = value;
      this._remove(existing);
      this._insertAtFront(existing);
      return;
    }

    // Evict LRU entry if at capacity
    if (this.map.size === this.capacity) {
      const lru = this.tail.prev!; // node just before tail sentinel
      this._remove(lru);
      this.map.delete(lru.key);
    }

    const node = new LRUNode(key, value);
    this._insertAtFront(node);
    this.map.set(key, node);
  }

  // --- Private helpers (all O(1)) ---

  private _remove(node: LRUNode): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  private _insertAtFront(node: LRUNode): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Optional: current size */
  get size(): number {
    return this.map.size;
  }

  /** Optional: ordered snapshot [MRU ... LRU] for debugging */
  snapshot(): [number, number][] {
    const result: [number, number][] = [];
    let cur = this.head.next;
    while (cur !== this.tail) {
      result.push([cur!.key, cur!.value]);
      cur = cur!.next;
    }
    return result;
  }
}
