    // Sentinel nodes (dummy keys/values, never accessed)
    this.head = new LRUNode<K, V>(null as unknown as K, null as unknown as V);
    this.tail = new LRUNode<K, V>(null as unknown as K, null as unknown as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /** O(1) — returns the value or undefined if not present */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    // Mark as most-recently-used
    this._remove(node);
    this._insertAfterHead(node);
    return node.value;
  }

  /** O(1) — inserts or updates; evicts LRU entry if over capacity */
  put(key: K, value: V): void {
    // Edge case: zero-capacity cache accepts nothing
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing) {
      // Update value and promote to MRU
      existing.value = value;
      this._remove(existing);
      this._insertAfterHead(existing);
      return;
    }

    // Evict LRU if at capacity
    if (this.map.size === this.capacity) {
      const lru = this.tail.prev!; // safe: sentinels guarantee non-null
      this._remove(lru);
      this.map.delete(lru.key);
    }

    const node = new LRUNode(key, value);
    this._insertAfterHead(node);
    this.map.set(key, node);
  }

  /** Current number of entries */
  get size(): number {
    return this.map.size;
  }

  // --- Private helpers ---

  /** Unlink a node from the list — O(1) */
  private _remove(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /** Insert a node immediately after head (MRU position) — O(1) */
  private _insertAfterHead(node: LRUNode<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }
}
```

---

### Edge Cases Handled

| Edge Case | Behaviour |
|---|---|
| `capacity = 0` | `put` is a no-op; `get` always returns `undefined` |
| `get` on missing key | Returns `undefined` (not -1, to be type-safe in generic form) |
| `put` duplicate key | Updates value in-place, promotes to MRU — **no** eviction |
| Single-slot cache (`capacity = 1`) | Every new distinct key evicts the previous one |
| `put` then `get` same key multiple times | Node stays at MRU; never evicted while being used |
| Non-integer / negative capacity | Throws `RangeError` at construction time |

