## Implementation

```typescript
/**
 * Doubly linked list node
 */
class Node<K, V> {
  key: K;
  value: V;
  prev: Node<K, V> | null = null;
  next: Node<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations
 * - Most recently used items are near HEAD
 * - Least recently used items are near TAIL
 */
class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly cache: Map<K, Node<K, V>>;

  // Sentinel nodes eliminate null checks at list boundaries
  private readonly head: Node<K, V>; // dummy head (MRU side)
  private readonly tail: Node<K, V>; // dummy tail (LRU side)

  constructor(capacity: number) {
    if (capacity <= 0 || !Number.isInteger(capacity)) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Initialize sentinel nodes
    this.head = new Node<K, V>(null as K, null as V);
    this.tail = new Node<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ───────────────────────────────────────────────────────────

  /**
   * Retrieve value by key.
   * Marks the item as most recently used.
   * @returns The value, or undefined if not found
   */
  get(key: K): V | undefined {
    const node = this.cache.get(key);

    if (!node) return undefined;

    // Move to front (mark as most recently used)
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * Evicts the least recently used item if at capacity.
   */
  put(key: K, value: V): void {
    const existing = this.cache.get(key);

    if (existing) {
      // Update value and mark as recently used
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU item before inserting if at capacity
    if (this.cache.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new Node(key, value);
    this.cache.set(key, newNode);
    this.insertAtFront(newNode);
  }

  /**
   * Remove a specific key from the cache.
   * @returns true if the key existed and was removed
   */
  delete(key: K): boolean {
    const node = this.cache.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.cache.delete(key);
    return true;
  }

  /** Remove all entries from the cache */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /** Check if a key exists (does NOT update recency) */
  has(key: K): boolean {
    return this.cache.has(key);
  }

  get size(): number {
    return this.cache.size;
  }

  /**
   * Returns keys from most-recently-used to least-recently-used
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }

    return result;
  }

  // ─── Private Helpers ──────────────────────────────────────────────────────

  /**
   * Insert a node directly after the head sentinel (MRU position)
   */
  private insertAtFront(node: Node<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Remove a node from its current position in the list
   */
  private removeNode(node: Node<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Help GC by clearing pointers
    node.prev = null;
    node.next = null;
  }

  /**
   * Move an existing node to the MRU position
   */
  private moveToFront(node: Node<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Remove the LRU item (node just before tail sentinel)
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev;

    // Guard: only sentinel nodes remain (empty cache - shouldn't happen)
    if (!lruNode || lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key);
  }
}
