   * Inserts or updates a key-value pair.
   * If at capacity, evicts the least-recently-used entry first.
   * Time: O(1)  Space: O(1)
   */
  put(key: K, value: V): void {
    const existing = this.cache.get(key);

    if (existing) {
      // Update value in-place and promote to front
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU entry before inserting when at capacity
    if (this.size === this.capacity) {
      this.evictLRU();
    }

    const node = new DLinkedNode(key, value);
    this.cache.set(key, node);
    this.insertAtFront(node);
    this.size++;
  }

  /**
   * Removes a key explicitly.
   * Returns true if the key existed, false otherwise.
   * Time: O(1)
   */
  delete(key: K): boolean {
    const node = this.cache.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.cache.delete(key);
    this.size--;
    return true;
  }

  /**
   * Returns true if the key exists WITHOUT updating recency.
   * Useful for "peek" semantics.
   * Time: O(1)
   */
  has(key: K): boolean {
    return this.cache.has(key);
  }

  /** Removes all entries. */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  get currentSize(): number {
    return this.size;
  }

  get maxCapacity(): number {
    return this.capacity;
  }

  /**
   * Returns keys ordered from most-recently-used to least-recently-used.
   * Useful for debugging / inspection.
   */
  keys(): K[] {
    const result: K[] = [];
    let curr = this.head.next;
    while (curr !== this.tail) {
      result.push(curr!.key as K);
      curr = curr!.next;
    }
    return result;
  }

  // ----------------------------------------------------------
  // PRIVATE HELPERS
  // ----------------------------------------------------------

  /** Insert a node immediately after the head sentinel (= most recent). */
  private insertAtFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Splice a node out of the list (does NOT update size or map). */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Null out pointers to help GC and catch stale-reference bugs
    node.prev = null;
    node.next = null;
  }

  /** Remove then re-insert at front — promotes to most-recently-used. */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Remove and return the node just before the tail sentinel (= LRU). */
  private evictLRU(): void {
    const lru = this.tail.prev!;
    // Guard: only the head sentinel can be adjacent to tail when empty,
    // and we never call this when size === 0.
    if (lru === this.head) return;

    this.removeNode(lru);
    this.cache.delete(lru.key as K);
    this.size--;
  }
}
