# LRU Cache Implementation in TypeScript

## Data Structure Choice

An LRU cache requires O(1) for both operations, which demands two complementary structures:

| Structure | Purpose | Operation |
|-----------|---------|-----------|
| **HashMap** | Key → Node lookup | O(1) get/set |
| **Doubly Linked List** | Tracks recency order | O(1) insert/delete with node reference |

A singly linked list would require O(n) deletion. An array would require O(n) shifting. The combination is the only way to achieve O(1) for both.

---

## Implementation

```typescript
// ─── Node definition ────────────────────────────────────────────────────────

class DLinkedNode<K, V> {
  constructor(
    public key: K | null = null,
    public value: V | null = null,
    public prev: DLinkedNode<K, V> | null = null,
    public next: DLinkedNode<K, V> | null = null
  ) {}
}

// ─── LRU Cache ──────────────────────────────────────────────────────────────

class LRUCache<K, V> {
  private readonly capacity: number;
  private size: number = 0;

  /** O(1) key → node lookup */
  private readonly map: Map<K, DLinkedNode<K, V>> = new Map();

  /**
   * Sentinel nodes eliminate null-checks on every insertion/deletion.
   *
   *  head ↔ [MRU ... LRU] ↔ tail
   *
   * head.next = most-recently used
   * tail.prev = least-recently used
   */
  private readonly head: DLinkedNode<K, V> = new DLinkedNode();
  private readonly tail: DLinkedNode<K, V> = new DLinkedNode();

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer (got ${capacity})`);
    }
    this.capacity = capacity;
    // Wire sentinels together
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Returns the value for `key`, or `undefined` if absent.
   * Marks the entry as most-recently used.   O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    this.moveToFront(node);
    return node.value as V;
  }

  /**
   * Inserts or updates a key-value pair.
   * Evicts the LRU entry when the cache is full.   O(1)
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value in-place and promote to MRU
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node = new DLinkedNode(key, value);
    this.map.set(key, node);
    this.addToFront(node);
    this.size++;

    if (this.size > this.capacity) {
      this.evictLRU();
    }
  }

  /**
   * Removes a specific key from the cache.   O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    this.size--;
    return true;
  }

  /** Removes all entries without resizing. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /** Current number of cached entries. */
  get length(): number {
    return this.size;
  }

  /** Returns entries from MRU → LRU (useful for debugging). */
  entries(): Array<[K, V]> {
    const result: Array<[K, V]> = [];
    let cur = this.head.next;
    while (cur !== this.tail) {
      result.push([cur!.key as K, cur!.value as V]);
      cur = cur!.next;
    }
    return result;
  }

  // ─── Private helpers ───────────────────────────────────────────────────────

  /** Inserts `node` immediately after the head sentinel (MRU position). */
  private addToFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Splices `node` out of its current position without freeing it. */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /** Moves an existing node to the MRU position. */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /** Removes the LRU node (tail.prev) and deletes it from the map. */
  private evictLRU(): void {
    const lru = this.tail.prev!;
    this.removeNode(lru);
    this.map.delete(lru.key as K);
    this.size--;
  }
}
