# LRU Cache Implementation in TypeScript

## Data Structure Choice

The key insight is combining two structures:
- **HashMap** → O(1) key lookup
- **Doubly Linked List** → O(1) node removal/insertion (with direct pointer)

Together they let us track both *existence* and *recency* simultaneously.

```typescript
/**
 * Node in our doubly linked list.
 * Each node holds a key (for reverse-lookup during eviction) and its value.
 */
class DLLNode<K, V> {
  constructor(
    public key: K,
    public value: V,
    public prev: DLLNode<K, V> | null = null,
    public next: DLLNode<K, V> | null = null
  ) {}
}

/**
 * LRU Cache with O(1) get and put operations.
 *
 * Architecture:
 * ┌─────┐     ┌─────┐     ┌─────┐     ┌─────┐
 * │HEAD │────▶│  A  │────▶│  B  │────▶│TAIL │   (MRU ← direction → LRU)
 * │dummy│◀────│     │◀────│     │◀────│dummy│
 * └─────┘     └─────┘     └─────┘     └─────┘
 *   Most Recently Used             Least Recently Used
 *
 * HEAD.next = Most Recent | TAIL.prev = Least Recent (eviction candidate)
 */
class LRUCache<K = number, V = number> {
  private capacity: number;
  private cache: Map<K, DLLNode<K, V>>;

  // Sentinel nodes eliminate null checks at list boundaries
  private head: DLLNode<K, V>; // dummy head (most recent side)
  private tail: DLLNode<K, V>; // dummy tail (least recent side)

  constructor(capacity: number) {
    if (capacity <= 0 || !Number.isInteger(capacity)) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Initialize sentinel nodes — they never hold real data
    this.head = new DLLNode<K, V>(null as K, null as V);
    this.tail = new DLLNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Retrieve a value by key. Returns -1 if not found.
   * Promotes the accessed node to Most Recently Used position.
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | -1 {
    const node = this.cache.get(key);

    if (!node) return -1;

    // Accessing makes it most recently used
    this.promoteToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * - Update: refresh value + promote to MRU
   * - Insert: add to MRU position, evict LRU if over capacity
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existing = this.cache.get(key);

    if (existing) {
      // Update existing node in-place, then promote
      existing.value = value;
      this.promoteToFront(existing);
      return;
    }

    // Evict before inserting to maintain capacity invariant
    if (this.cache.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new DLLNode(key, value);
    this.insertAtFront(newNode);
    this.cache.set(key, newNode);
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /**
   * Move an existing node to the MRU position (head.next).
   * Unlink from current position → relink at front.
   */
  private promoteToFront(node: DLLNode<K, V>): void {
    this.unlink(node);
    this.insertAtFront(node);
  }

  /**
   * Insert a node immediately after the head sentinel.
   *
   * Before: HEAD ←→ [firstNode]
   * After:  HEAD ←→ [node] ←→ [firstNode]
   */
  private insertAtFront(node: DLLNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;

    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Remove a node from its current position in the list.
   * The node's prev/next pointers become stale — always re-set after unlinking.
   */
  private unlink(node: DLLNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /**
   * Evict the Least Recently Used node (tail.prev sentinel's neighbor).
   * Must also remove from the HashMap using the node's stored key.
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: only evict real nodes (not the head sentinel)
    if (lruNode === this.head) return;

    this.unlink(lruNode);
    this.cache.delete(lruNode.key);
  }

  // ─── Introspection Utilities ───────────────────────────────────────────────

  /** Current number of entries */
  get size(): number {
    return this.cache.size;
  }

  /** Returns keys from MRU → LRU order (useful for debugging) */
  toOrderedKeys(): K[] {
    const keys: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      keys.push(current!.key);
      current = current!.next;
    }

    return keys;
  }

  /** Visual snapshot of cache state */
  toString(): string {
    const ordered = this.toOrderedKeys().join(" → ");
    return `LRUCache(${this.cache.size}/${this.capacity}) [MRU] ${ordered} [LRU]`;
  }
}
