# LRU Cache Implementation in TypeScript

## Data Structure Choice

**HashMap + Doubly Linked List** is the optimal combination:

- **HashMap** → O(1) key lookup to find any node instantly
- **Doubly Linked List** → O(1) insertion/deletion at any position (with a node reference)
- **Sentinel nodes** (dummy head/tail) → Eliminate null checks and edge cases in pointer manipulation

A singly linked list would require O(n) deletion since you can't access the previous node. Arrays would require O(n) shifts.

```typescript
// ─── Node Definition ────────────────────────────────────────────────────────

interface CacheNode<K, V> {
  key: K;
  value: V;
  prev: CacheNode<K, V> | null;
  next: CacheNode<K, V> | null;
}

function createNode<K, V>(key: K, value: V): CacheNode<K, V> {
  return { key, value, prev: null, next: null };
}

// ─── LRU Cache Class ─────────────────────────────────────────────────────────

class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, CacheNode<K, V>>;

  // Sentinel nodes — never hold real data, just anchor the list
  // Layout: head <-> [MRU ... LRU] <-> tail
  private readonly head: CacheNode<K, V>; // Most-Recently-Used side
  private readonly tail: CacheNode<K, V>; // Least-Recently-Used side

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinels with placeholder keys/values
    this.head = createNode<K, V>(null as K, null as V);
    this.tail = createNode<K, V>(null as K, null as V);

    // Wire sentinels together to form an empty list
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Returns the value for key, or undefined if not found.
   * Promotes the accessed node to MRU position. O(1).
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    this.promoteToMRU(node);
    return node.value;
  }

  /**
   * Inserts or updates a key-value pair.
   * - Update: refreshes value and promotes to MRU.
   * - Insert: adds at MRU position; evicts LRU if over capacity. O(1).
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update in-place and promote
      existing.value = value;
      this.promoteToMRU(existing);
      return;
    }

    // Evict before inserting to keep capacity accurate
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    const node = createNode(key, value);
    this.map.set(key, node);
    this.insertAtMRU(node);
  }

  /**
   * Explicitly removes a key. Returns true if the key existed. O(1).
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Returns the number of items currently in the cache. */
  get size(): number {
    return this.map.size;
  }

  /** Returns keys from MRU → LRU order (useful for debugging/testing). */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /**
   * Removes a node from its current position in the list.
   * Requires both prev and next to be non-null (guaranteed for non-sentinel nodes).
   *
   *  Before: [prev] <-> [node] <-> [next]
   *  After:  [prev] <-> [next]
   */
  private removeNode(node: CacheNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Dangling pointers cleared to help GC and catch bugs early
    node.prev = null;
    node.next = null;
  }

  /**
   * Inserts a node immediately after the head sentinel (MRU position).
   *
   *  Before: [head] <-> [first]
   *  After:  [head] <-> [node] <-> [first]
   */
  private insertAtMRU(node: CacheNode<K, V>): void {
    const first = this.head.next!;
    node.next = first;
    node.prev = this.head;
    this.head.next = node;
    first.prev = node;
  }

  /** Moves an existing node to the MRU position. O(1). */
  private promoteToMRU(node: CacheNode<K, V>): void {
    this.removeNode(node);
    this.insertAtMRU(node);
  }

  /**
   * Evicts the LRU node (immediately before the tail sentinel).
   * Called only when map.size === capacity, so tail.prev is always a real node.
   */
  private evictLRU(): void {
    const lru = this.tail.prev!;
    // tail.prev === head only when cache is empty — capacity > 0 guards this
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

