```typescript
/**
 * Doubly linked list node
 */
class LRUNode<K, V> {
  key: K;
  value: V;
  prev: LRUNode<K, V> | null = null;
  next: LRUNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations.
 *
 * Architecture:
 *   HEAD <-> [MRU] <-> ... <-> [LRU] <-> TAIL
 *
 * HEAD and TAIL are sentinel nodes (never hold real data).
 * Most Recently Used (MRU) is always adjacent to HEAD.
 * Least Recently Used (LRU) is always adjacent to TAIL.
 */
class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, LRUNode<K, V>>;

  // Sentinel nodes eliminate null-checks on boundary conditions
  private readonly head: LRUNode<K, V>; // dummy head (MRU side)
  private readonly tail: LRUNode<K, V>; // dummy tail (LRU side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinels with placeholder keys/values
    this.head = new LRUNode<K, V>(null as K, null as V);
    this.tail = new LRUNode<K, V>(null as K, null as V);

    // Link sentinels together
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Core Operations ─────────────────────────────────────────────────────────

  /**
   * Retrieve value by key. Marks entry as most recently used.
   * @returns The cached value, or undefined if not found
   * Time:  O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);

    if (!node) {
      return undefined; // Cache miss
    }

    // Promote to MRU position (move to front)
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * If at capacity, evicts the least recently used entry first.
   * Time:  O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update existing entry and promote it
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU if at capacity BEFORE inserting
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    // Insert new node at MRU position
    const newNode = new LRUNode(key, value);
    this.map.set(key, newNode);
    this.insertAtFront(newNode);
  }

  // ─── Linked List Helpers ──────────────────────────────────────────────────────

  /**
   * Remove a node from its current position in the list.
   * The node's prev/next pointers are intentionally left intact
   * so callers can re-insert without re-reading those fields.
   */
  private removeNode(node: LRUNode<K, V>): void {
    const prev = node.prev!; // Non-null: sentinels guarantee boundaries
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
  }

  /**
   * Insert a node immediately after the HEAD sentinel (MRU position).
   */
  private insertAtFront(node: LRUNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Move an existing node to the MRU position.
   * Combines remove + insertAtFront in a single logical operation.
   */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Remove the LRU node (adjacent to TAIL) and delete from map.
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: only evict real nodes, not the sentinel itself
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }

  // ─── Utility / Inspection ────────────────────────────────────────────────────

  /** Current number of entries in the cache */
  get size(): number {
    return this.map.size;
  }

  /** Whether the cache has an entry for the given key (without updating recency) */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /** Remove a specific key from the cache */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Remove all entries */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Snapshot of keys from MRU → LRU order (for debugging/testing).
   * Does NOT affect recency of any entry.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }

    return result;
  }

  toString(): string {
    return `LRUCache(${this.size}/${this.capacity}) [${this.keys().join(' → ')}]`;
  }
}
