# LRU Cache Implementation in TypeScript

## Data Structure Choice

An LRU cache requires O(1) for both `get` and `put`. This demands two complementary structures:

| Structure | Purpose | Why |
|-----------|---------|-----|
| **HashMap** | Key → Node lookup | O(1) access by key |
| **Doubly Linked List** | Usage order tracking | O(1) insertion/deletion at any position |

A singly linked list would require O(n) deletion. An array would require O(n) shifting. Together, the HashMap + Doubly Linked List achieves O(1) for all operations.

---

## Implementation

```typescript
// ─── Node Definition ───────────────────────────────────────────────────────────

class DLinkedNode<K, V> {
  constructor(
    public key: K | null = null,
    public value: V | null = null,
    public prev: DLinkedNode<K, V> | null = null,
    public next: DLinkedNode<K, V> | null = null
  ) {}
}

// ─── LRU Cache ─────────────────────────────────────────────────────────────────

class LRUCache<K, V> {
  private readonly capacity: number;
  private size: number;
  private cache: Map<K, DLinkedNode<K, V>>;

  // Sentinel nodes eliminate null checks on every operation.
  // head.next = most recently used
  // tail.prev = least recently used
  private head: DLinkedNode<K, V>; // dummy head (MRU side)
  private tail: DLinkedNode<K, V>; // dummy tail (LRU side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.size = 0;
    this.cache = new Map();

    // Initialize sentinel nodes and link them together
    this.head = new DLinkedNode<K, V>();
    this.tail = new DLinkedNode<K, V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ──────────────────────────────────────────────────────────────

  /**
   * Retrieves value by key. Returns undefined if not found.
   * Marks the accessed entry as most recently used.
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.cache.get(key);

    if (node === undefined) {
      return undefined; // Cache miss
    }

    // Promote to most recently used
    this.moveToFront(node);
    return node.value as V;
  }

  /**
   * Inserts or updates a key-value pair.
   * If at capacity, evicts the least recently used entry first.
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode !== undefined) {
      // Update existing entry and promote it
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU entry if at capacity
    if (this.size === this.capacity) {
      this.evictLRU();
    }

    // Insert new node at the front (MRU position)
    const newNode = new DLinkedNode(key, value);
    this.cache.set(key, newNode);
    this.addToFront(newNode);
    this.size++;
  }

  /**
   * Removes a key from the cache explicitly.
   * Returns true if the key existed, false otherwise.
   * Time: O(1)
   */
  delete(key: K): boolean {
    const node = this.cache.get(key);

    if (node === undefined) {
      return false;
    }

    this.removeNode(node);
    this.cache.delete(key);
    this.size--;
    return true;
  }

  /**
   * Checks key existence without affecting usage order.
   * Time: O(1)
   */
  has(key: K): boolean {
    return this.cache.has(key);
  }

  /** Removes all entries from the cache. */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.size = 0;
  }

  /** Returns current number of entries. */
  get length(): number {
    return this.size;
  }

  /**
   * Returns keys ordered from most to least recently used.
   * Useful for debugging and inspection.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key as K);
      current = current!.next;
    }

    return result;
  }

  // ─── Private Helpers ─────────────────────────────────────────────────────────

  /**
   * Inserts a node immediately after the dummy head (MRU position).
   *
   *  [head] <──> [node] <──> [head.next]
   */
  private addToFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Splices a node out of the list without deallocating it.
   *
   *  [node.prev] <──> [node] <──> [node.next]
   *       becomes
   *  [node.prev] <──────────────> [node.next]
   */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  /** Promotes an existing node to the MRU position. */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /** Removes the least recently used node (just before the dummy tail). */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard against evicting a sentinel (shouldn't happen if size > 0)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key as K);
    this.size--;
  }
}
