# LRU Cache Implementation in TypeScript

## Data Structure Choice

The key insight is combining two structures:
- **HashMap** → O(1) key lookup
- **Doubly Linked List** → O(1) node removal/insertion (we hold direct references, no traversal)

Together they form a "LinkedHashMap" — the list maintains recency order, the map provides instant access to any node.

```typescript
/**
 * Node in our doubly-linked list
 * Each node holds a key (for reverse-lookup during eviction) and a value
 */
class LRUNode<K, V> {
  constructor(
    public key: K,
    public value: V,
    public prev: LRUNode<K, V> | null = null,
    public next: LRUNode<K, V> | null = null
  ) {}
}

/**
 * LRU Cache with O(1) get and put operations
 *
 * Architecture:
 *   HEAD <-> [MRU] <-> ... <-> [LRU] <-> TAIL
 *
 * HEAD and TAIL are sentinel nodes — they simplify edge cases
 * by ensuring we never operate on null pointers at list boundaries.
 */
class LRUCache<K, V> {
  private capacity: number;
  private cache: Map<K, LRUNode<K, V>>;
  private head: LRUNode<K, V>; // Sentinel: Most Recently Used side
  private tail: LRUNode<K, V>; // Sentinel: Least Recently Used side

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new RangeError(`Capacity must be positive, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Sentinel nodes eliminate null checks at list boundaries
    this.head = new LRUNode<K, V>(null as K, null as V);
    this.tail = new LRUNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Retrieve a value — O(1)
   * A cache hit promotes the node to Most Recently Used position
   */
  get(key: K): V | undefined {
    const node = this.cache.get(key);

    if (!node) {
      return undefined; // Cache miss
    }

    // Promote to MRU position
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a value — O(1)
   * - Update: refresh value and promote to MRU
   * - Insert: add to MRU; evict LRU if over capacity
   */
  put(key: K, value: V): void {
    const existing = this.cache.get(key);

    if (existing) {
      // Update existing node — no eviction needed
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU entry before inserting if at capacity
    if (this.cache.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new LRUNode(key, value);
    this.cache.set(key, newNode);
    this.insertAtFront(newNode);
  }

  /**
   * Peek at a value WITHOUT updating recency — O(1)
   * Useful for inspection without side effects
   */
  peek(key: K): V | undefined {
    return this.cache.get(key)?.value;
  }

  /**
   * Explicitly remove a key — O(1)
   * Returns true if the key existed
   */
  delete(key: K): boolean {
    const node = this.cache.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.cache.delete(key);
    return true;
  }

  /** Current number of entries */
  get size(): number {
    return this.cache.size;
  }

  /** Check if a key exists without affecting recency */
  has(key: K): boolean {
    return this.cache.has(key);
  }

  /** Remove all entries */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /** Snapshot of keys from MRU → LRU (for debugging/testing) */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ─── Private List Operations ──────────────────────────────────────────────

  /**
   * Detach a node from its current list position
   *
   * Before: [prev] <-> [node] <-> [next]
   * After:  [prev] <-> [next]    (node is now "floating")
   */
  private removeNode(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Clear pointers to avoid memory leaks in evicted nodes
    node.prev = null;
    node.next = null;
  }

  /**
   * Insert a "floating" node directly after HEAD (MRU position)
   *
   * Before: HEAD <-> [current-front]
   * After:  HEAD <-> [node] <-> [current-front]
   */
  private insertAtFront(node: LRUNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Combine remove + insert for a cache-hit promotion */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Evict the node just before TAIL (LRU position)
   * The node's key is stored on the node itself — critical for O(1) map removal
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: only evict real nodes, not the head sentinel
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key); // O(1) because node carries its key
  }
}
