## Implementation

```typescript
class ListNode<K, V> {
  key: K;
  value: V;
  prev: ListNode<K, V> | null = null;
  next: ListNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

class LRUCache<K, V> {
  private readonly capacity: number;
  private map: Map<K, ListNode<K, V>>;

  // Sentinel nodes eliminate null checks on list operations
  private head: ListNode<K, V>; // Most recently used end
  private tail: ListNode<K, V>; // Least recently used end

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinels with dummy values
    this.head = new ListNode<K, V>(null as K, null as V);
    this.tail = new ListNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * O(1) - Returns value or undefined if key doesn't exist.
   * Moves accessed node to front (most recently used).
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    this.moveToFront(node);
    return node.value;
  }

  /**
   * O(1) - Inserts or updates a key-value pair.
   * Evicts least recently used entry if over capacity.
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update existing node and promote it
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU entry before inserting if at capacity
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new ListNode(key, value);
    this.map.set(key, newNode);
    this.insertAtFront(newNode);
  }

  /**
   * O(1) - Explicitly remove a key from the cache.
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /**
   * Returns current number of entries.
   */
  get size(): number {
    return this.map.size;
  }

  /**
   * Checks if a key exists without updating recency.
   * Useful for cache inspection without side effects.
   */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /**
   * Clears all entries.
   */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Returns keys from most → least recently used (for debugging/inspection).
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /** Removes a node from its current position in the list. */
  private removeNode(node: ListNode<K, V>): void {
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    // Nullify pointers to prevent memory leaks / dangling refs
    node.prev = null;
    node.next = null;
  }

  /** Inserts a node immediately after the head sentinel (MRU position). */
  private insertAtFront(node: ListNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Combines remove + insert for promoting an existing node. */
  private moveToFront(node: ListNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Removes the LRU entry (node before tail sentinel). */
  private evictLRU(): void {
    const lruNode = this.tail.prev;

    // Guard: only evict if list isn't empty (sentinels aren't adjacent)
    if (!lruNode || lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
