cache.put("c", 99); // Update value + promote "c"
console.log(cache.keys()); // ["c", "d", "a"]
console.log(cache.get("c")); // 99

// ─── Edge Case: Capacity of 1 ──────────────────────────────────────────────
const tiny = new LRUCache<string, string>(1);
tiny.put("x", "foo");
tiny.put("y", "bar"); // evicts "x"
console.log(tiny.get("x")); // undefined
console.log(tiny.get("y")); // "bar"

// ─── Edge Case: Invalid capacity ───────────────────────────────────────────
