# LRU Cache Implementation in TypeScript

## Data Structure Choice

An LRU cache requires O(1) for both operations, which demands two complementary structures:

| Structure | Purpose | Why |
|-----------|---------|-----|
| **HashMap** | Key → Node lookup | O(1) access by key |
| **Doubly Linked List** | Tracks recency order | O(1) insertion/deletion at any position |

A singly linked list would require O(n) deletion. An array would require O(n) shifting. Together, HashMap + DLL gives us exactly what we need.

```
HEAD ↔ [most recent] ↔ ... ↔ [least recent] ↔ TAIL
```

---

## Implementation

```typescript
/**
 * Node in our doubly linked list.
 * Stores the key so we can delete from the map during eviction.
 */
class DLLNode<K, V> {
  key: K;
  value: V;
  prev: DLLNode<K, V> | null = null;
  next: DLLNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations.
 *
 * Eviction Policy: When capacity is exceeded, the least recently
 * used item (adjacent to TAIL sentinel) is evicted.
 *
 * Recency Convention: HEAD.next = most recently used
 *                     TAIL.prev = least recently used
 */
class LRUCache<K, V> {
  private capacity: number;
  private map: Map<K, DLLNode<K, V>>;

  // Sentinel nodes eliminate null checks at list boundaries
  private head: DLLNode<K, V>; // Dummy head (most recent side)
  private tail: DLLNode<K, V>; // Dummy tail (least recent side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes — they never hold real data
    this.head = new DLLNode<K, V>(null as K, null as V);
    this.tail = new DLLNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─────────────────────────────────────────────
  // Public API
  // ─────────────────────────────────────────────

  /**
   * Retrieve a value by key.
   * Marks the item as most recently used.
   * Returns undefined if key doesn't exist.
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    // Touch: move to front (most recently used)
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * If key exists, update value and mark as most recently used.
   * If at capacity, evict the least recently used item first.
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update existing — no capacity change needed
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict before inserting if at capacity
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    const newNode = new DLLNode(key, value);
    this.map.set(key, newNode);
    this.insertAtFront(newNode);
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * Time: O(1) | Space: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /**
   * Remove all entries from the cache.
   * Time: O(1) | Space: O(1)
   */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─────────────────────────────────────────────
  // Introspection (useful for debugging/testing)
  // ─────────────────────────────────────────────

  get size(): number {
    return this.map.size;
  }

  has(key: K): boolean {
    return this.map.has(key);
  }

  /**
   * Returns keys from most-recently-used to least-recently-used.
   * Useful for debugging and testing.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ─────────────────────────────────────────────
  // Private Helpers — all O(1)
  // ─────────────────────────────────────────────

  /**
   * Insert a node immediately after HEAD (most-recent position).
   *
   * Before: HEAD ↔ X ↔ ...
   * After:  HEAD ↔ node ↔ X ↔ ...
   */
  private insertAtFront(node: DLLNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Splice a node out of its current position in the list.
   * Does NOT update the map — caller is responsible.
   *
   * Before: A ↔ node ↔ B
   * After:  A ↔ B        (node is now detached)
   */
  private removeNode(node: DLLNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Detach to help garbage collection
    node.prev = null;
    node.next = null;
  }

  /**
   * Move an existing node to the front (most-recently-used position).
   * Equivalent to remove + insertAtFront.
   */
  private moveToFront(node: DLLNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Evict the least-recently-used node (TAIL.prev).
   * Removes from both the list and the map.
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;
    // Guard: only sentinel nodes remain (shouldn't happen if capacity >= 1)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
