 * Doubly-linked list node for LRU Cache
 */
class LRUNode<K, V> {
  key: K;
  value: V;
  prev: LRUNode<K, V> | null = null;
  next: LRUNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations
 *
 * Architecture:
 *   HEAD <-> [most recent] <-> ... <-> [least recent] <-> TAIL
 *
 * - HEAD.next = most recently used
 * - TAIL.prev = least recently used (eviction candidate)
 */
class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly cache: Map<K, LRUNode<K, V>>;

  // Sentinel nodes — never hold real data, never removed
  private readonly head: LRUNode<K, V>;  // dummy head (most-recent side)
  private readonly tail: LRUNode<K, V>;  // dummy tail (least-recent side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Initialize sentinels with dummy values (never exposed externally)
    this.head = new LRUNode<K, V>(null as K, null as V);
    this.tail = new LRUNode<K, V>(null as K, null as V);

    // Link sentinels: HEAD <-> TAIL
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Retrieve a value by key.
   * Marks the entry as most recently used.
   *
   * @returns The value, or undefined if not found
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.cache.get(key);

    if (!node) {
      return undefined;  // Cache miss
    }

    // Promote to most-recently-used position
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * Evicts the least recently used entry if at capacity.
   *
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update existing — promote and refresh value
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU entry if at capacity BEFORE inserting
    if (this.cache.size >= this.capacity) {
      this.evictLRU();
    }

    // Insert new node at front (most recently used)
    const newNode = new LRUNode(key, value);
    this.cache.set(key, newNode);
    this.insertAtFront(newNode);
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   *
   * Time: O(1) | Space: O(1)
   */
  delete(key: K): boolean {
    const node = this.cache.get(key);

    if (!node) {
      return false;
    }

    this.removeNode(node);
    this.cache.delete(key);
    return true;
  }

  /**
   * Check if a key exists WITHOUT updating access order.
   * Useful for read-only existence checks.
   *
   * Time: O(1)
   */
  has(key: K): boolean {
    return this.cache.has(key);
  }

  /** Current number of entries in the cache */
  get size(): number {
    return this.cache.size;
  }

  /** Returns keys from most-recently-used to least-recently-used */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }

    return result;
  }

  /** Remove all entries */
  clear(): void {
    this.cache.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /**
   * Insert a node immediately after HEAD (most-recent position)
   *
   * Before: HEAD <-> firstNode
   * After:  HEAD <-> node <-> firstNode
   */
  private insertAtFront(node: LRUNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Detach a node from its current list position.
   * Works correctly even if node is at head or tail position.
   *
   * Before: A <-> node <-> B
   * After:  A <-> B  (node is isolated)
   */
  private removeNode(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Clear pointers to prevent memory leaks
    node.prev = null;
    node.next = null;
  }

  /**
   * Move an existing node to the most-recently-used position.
   * Combines remove + insertAtFront for clarity.
   */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Evict the least-recently-used entry (node before TAIL).
   * Assumes cache is non-empty (always true when called from put()).
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: should never be the sentinel HEAD, but safety first
    if (lruNode === this.head) {
      return;
    }

    this.removeNode(lruNode);
    this.cache.delete(lruNode.key);
  }
}
