## Data Structure Choice

The key insight is combining two structures:
- **HashMap** → O(1) key lookup
- **Doubly Linked List** → O(1) node removal/insertion (we hold direct node references)

A singly linked list would require O(n) traversal to find previous nodes. An array would require O(n) shifts. Together, these give us true O(1) for both operations.

```typescript
/**
 * Node in our doubly linked list
 * Each node holds both its key (for reverse-lookup during eviction) and value
 */
class LRUNode<K, V> {
  key: K;
  value: V;
  prev: LRUNode<K, V> | null = null;
  next: LRUNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations
 *
 * Mental model: Imagine a queue where:
 * - HEAD.next = Most Recently Used (MRU)
 * - TAIL.prev = Least Recently Used (LRU) ← eviction candidate
 *
 * [HEAD] <-> [MRU] <-> [...] <-> [LRU] <-> [TAIL]
 *
 * Sentinel nodes (HEAD/TAIL) eliminate null-check edge cases at boundaries
 */
class LRUCache<K = number, V = number> {
  private readonly capacity: number;
  private readonly map: Map<K, LRUNode<K, V>>;

  // Sentinel nodes — never hold real data, simplify boundary logic
  private readonly head: LRUNode<K, V>;
  private readonly tail: LRUNode<K, V>;

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new RangeError(`Capacity must be positive, received: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinels with dummy values
    this.head = new LRUNode<K, V>(null as K, null as V);
    this.tail = new LRUNode<K, V>(null as K, null as V);

    // Wire sentinels together — the list starts empty
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Core Operations ─────────────────────────────────────────────────────────

  /**
   * O(1) — Retrieve value and promote node to MRU position
   * Returns -1 if key doesn't exist (LeetCode convention; adapt as needed)
   */
  get(key: K): V | -1 {
    const node = this.map.get(key);

    if (!node) return -1; // Cache miss

    // Promote to most-recently-used position
    this.moveToFront(node);
    return node.value;
  }

  /**
   * O(1) — Insert or update a key-value pair
   * If at capacity, evicts the least-recently-used entry first
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update existing — just refresh value and promote
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU if we're at capacity BEFORE inserting
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    // Insert new node at MRU position
    const newNode = new LRUNode(key, value);
    this.map.set(key, newNode);
    this.insertAtFront(newNode);
  }

  // ─── Private Helpers ──────────────────────────────────────────────────────────

  /**
   * Remove node from its current position, re-insert at front (MRU)
   * Combining these two operations is the heart of the O(1) trick
   */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Splice a node out of the linked list
   * Sentinels mean we NEVER have to check for null neighbors
   */
  private removeNode(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
  }

  /**
   * Insert node immediately after HEAD (MRU position)
   */
  private insertAtFront(node: LRUNode<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Remove the LRU node (just before TAIL) from both list and map
   * The node stores its key — that's why nodes carry keys, not just values
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: only evict real nodes, not the HEAD sentinel
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }

  // ─── Introspection (Useful for Testing) ──────────────────────────────────────

  get size(): number {
    return this.map.size;
  }

  /**
   * Returns keys from MRU → LRU order (great for debugging/testing)
   */
  toOrderedKeys(): K[] {
    const keys: K[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      keys.push(current!.key);
      current = current!.next;
    }

    return keys;
  }
}
