# LRU Cache Implementation in TypeScript

## Data Structure Choice

The optimal solution combines two data structures:

- **HashMap** (`Map<K, Node<K,V>>`): Provides O(1) key lookups
- **Doubly Linked List**: Maintains access order with O(1) node removal/insertion

A singly linked list would require O(n) removal. An array would require O(n) shifts. Together, these give us O(1) for both operations.

```typescript
// ============================================================
// Node definition for the doubly linked list
// ============================================================
class DLinkedNode<K, V> {
  key: K | null;
  value: V | null;
  prev: DLinkedNode<K, V> | null = null;
  next: DLinkedNode<K, V> | null = null;

  constructor(key: K | null = null, value: V | null = null) {
    this.key = key;
    this.value = value;
  }
}

// ============================================================
// LRU Cache — O(1) get and put
//
// Layout of the doubly linked list:
//   head <-> [MRU] <-> ... <-> [LRU] <-> tail
//
// head and tail are sentinel nodes (never hold real data).
// Most-recently-used (MRU) sits just after head.
// Least-recently-used (LRU) sits just before tail.
// ============================================================
class LRUCache<K = number, V = number> {
  private readonly capacity: number;
  private readonly cache: Map<K, DLinkedNode<K, V>>;
  private readonly head: DLinkedNode<K, V>; // sentinel
  private readonly tail: DLinkedNode<K, V>; // sentinel
  private size: number;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer (got ${capacity})`);
    }
    this.capacity = capacity;
    this.cache = new Map();
    this.size = 0;

    // Sentinel nodes eliminate null-checks on every insertion/removal
    this.head = new DLinkedNode<K, V>();
    this.tail = new DLinkedNode<K, V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ----------------------------------------------------------
  // PUBLIC API
  // ----------------------------------------------------------

  /**
   * Returns the value for `key`, or -1 if not found.
   * Marks the accessed node as most-recently-used.
   * Time: O(1)  Space: O(1)
   */
  get(key: K): V | -1 {
    const node = this.cache.get(key);
    if (!node) return -1;

    // Promote to MRU position
    this.moveToFront(node);
    return node.value as V;
  }

  /**
   * Inserts or updates the value for `key`.
   * If the cache is at capacity, evicts the LRU entry first.
   * Time: O(1)  Space: O(1)
   */
  put(key: K, value: V): void {
    const existing = this.cache.get(key);

    if (existing) {
      // Update value in-place, then promote
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    // Evict LRU before adding if we're at capacity
    if (this.size === this.capacity) {
      this.evictLRU();
    }

    const node = new DLinkedNode(key, value);
    this.cache.set(key, node);
    this.addToFront(node);
    this.size++;
  }

  /** Current number of entries in the cache. */
  get length(): number {
    return this.size;
  }

  /** Returns a snapshot of keys from MRU → LRU (useful for debugging). */
  keys(): K[] {
    const result: K[] = [];
    let cur = this.head.next;
    while (cur && cur !== this.tail) {
      result.push(cur.key as K);
      cur = cur.next;
    }
    return result;
  }

  // ----------------------------------------------------------
  // PRIVATE HELPERS
  // ----------------------------------------------------------

  /**
   * Inserts `node` immediately after the head sentinel (MRU position).
   */
  private addToFront(node: DLinkedNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Removes `node` from its current position in the list.
   * Does NOT update size or the HashMap — callers handle that.
   */
  private removeNode(node: DLinkedNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Null out pointers to help GC and prevent stale references
    node.prev = null;
    node.next = null;
  }

  /**
   * Moves an existing node to the MRU position (head.next).
   */
  private moveToFront(node: DLinkedNode<K, V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /**
   * Removes the LRU node (tail.prev) and purges it from the HashMap.
   */
  private evictLRU(): void {
    const lru = this.tail.prev!;
    // Guard against an empty list (tail.prev === head)
    if (lru === this.head) return;

    this.removeNode(lru);
    this.cache.delete(lru.key as K);
    this.size--;
  }
}
