# LRU Cache Implementation in TypeScript

## Data Structure Choice

**Doubly Linked List + HashMap** is the optimal combination:

- **HashMap** `{key → node}`: O(1) lookup by key
- **Doubly Linked List**: O(1) insertion/deletion when you have a node reference (no traversal needed)
- Together they enable O(1) `get` and `put` by using the map to find nodes instantly, then relinking pointers

A singly linked list would require O(n) deletion since you can't access the previous node. An array would require O(n) shifts.

```typescript
// ─── Node Definition ────────────────────────────────────────────────────────

interface Node<K, V> {
  key: K;
  value: V;
  prev: Node<K, V> | null;
  next: Node<K, V> | null;
}

function createNode<K, V>(key: K, value: V): Node<K, V> {
  return { key, value, prev: null, next: null };
}

// ─── LRU Cache ──────────────────────────────────────────────────────────────

class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, Node<K, V>>;

  // Sentinel nodes eliminate null checks at list boundaries
  // Layout: head <-> [MRU ... LRU] <-> tail
  private readonly head: Node<K, V>; // Most-recently-used end
  private readonly tail: Node<K, V>; // Least-recently-used end

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels carry no real data — they just anchor the list ends
    this.head = createNode<K, V>(null as K, null as V);
    this.tail = createNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Public API ─────────────────────────────────────────────────────────────

  /**
   * Returns the value for `key`, or `undefined` if not present.
   * Marks the accessed entry as most-recently-used.
   * Time: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    this.moveToFront(node); // Access = recently used
    return node.value;
  }

  /**
   * Inserts or updates `key` with `value`.
   * If at capacity, evicts the least-recently-used entry first.
   * Time: O(1)
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      existing.value = value;   // Update in-place — no eviction needed
      this.moveToFront(existing);
      return;
    }

    // Evict LRU entry before inserting when at capacity
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    const node = createNode(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  /**
   * Removes a key explicitly.
   * Returns true if the key existed, false otherwise.
   * Time: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Returns current number of entries. */
  get size(): number {
    return this.map.size;
  }

  /** True if the key exists (without updating recency). */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /** Removes all entries. */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Returns keys from most-recently-used to least-recently-used.
   * Useful for debugging/inspection.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ── Private Helpers ────────────────────────────────────────────────────────

  /** Detaches a node from its current position in the list. */
  private removeNode(node: Node<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Leave node.prev/next dangling — node is discarded after this
  }

  /** Inserts a node immediately after the head sentinel (MRU position). */
  private insertAtFront(node: Node<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Moves an existing node to the MRU position. */
  private moveToFront(node: Node<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Removes the node just before the tail sentinel (LRU position). */
  private evictLRU(): void {
    const lru = this.tail.prev!;
    // Guard: only evict if there's a real node (not the head sentinel)
    if (lru === this.head) return;

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}
