# LRU Cache Implementation in TypeScript

## Data Structure Choice

The key insight is combining two structures:
- **HashMap** → O(1) key lookup
- **Doubly Linked List** → O(1) insertion/deletion at any position (with node reference)

Together they form the perfect partnership: the map stores `key → node` references, while the list maintains recency order. No shifting, no searching — just pointer rewiring.

```typescript
// ============================================================
// Core Node & Type Definitions
// ============================================================

interface CacheNode<K, V> {
  key: K;
  value: V;
  prev: CacheNode<K, V> | null;
  next: CacheNode<K, V> | null;
}

interface CacheStats {
  hits: number;
  misses: number;
  evictions: number;
  hitRate: string;
}

// ============================================================
// LRU Cache Implementation
// ============================================================

class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, CacheNode<K, V>>;

  // Sentinel nodes eliminate null checks at list boundaries
  // head.next = most recently used
  // tail.prev = least recently used
  private readonly head: CacheNode<K, V>;
  private readonly tail: CacheNode<K, V>;

  // Optional: built-in statistics tracking
  private stats = { hits: 0, misses: 0, evictions: 0 };

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes (values are placeholders, never exposed)
    this.head = this.createNode(null as K, null as V);
    this.tail = this.createNode(null as K, null as V);

    // Link sentinels: head <-> tail (empty list)
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Public API ──────────────────────────────────────────────

  /**
   * Retrieve value by key. Marks the entry as most-recently-used.
   * Returns undefined for cache misses (avoids null/undefined ambiguity).
   * O(1) time complexity.
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);

    if (!node) {
      this.stats.misses++;
      return undefined;
    }

    // Promote to most-recently-used position
    this.moveToFront(node);
    this.stats.hits++;

    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * If at capacity, evicts the least-recently-used entry.
   * O(1) time complexity.
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update value and promote — no eviction needed
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU entry if at capacity before inserting
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    // Create and insert the new node at the front
    const newNode = this.createNode(key, value);
    this.insertAtFront(newNode);
    this.map.set(key, newNode);
  }

  /**
   * Remove a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * O(1) time complexity.
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /** Check existence without affecting recency order */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /** Wipe all entries, reset stats */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
    this.stats = { hits: 0, misses: 0, evictions: 0 };
  }

  get size(): number {
    return this.map.size;
  }

  /** Returns entries from MRU → LRU order */
  getStats(): CacheStats {
    const total = this.stats.hits + this.stats.misses;
    return {
      ...this.stats,
      hitRate: total === 0 ? "N/A" : `${((this.stats.hits / total) * 100).toFixed(1)}%`,
    };
  }

  /** Snapshot of current cache state, MRU → LRU */
  toArray(): Array<{ key: K; value: V }> {
    const result: Array<{ key: K; value: V }> = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push({ key: current!.key, value: current!.value });
      current = current!.next;
    }

    return result;
  }

  // ── Private Helpers ─────────────────────────────────────────

  private createNode(key: K, value: V): CacheNode<K, V> {
    return { key, value, prev: null, next: null };
  }

  /**
   * Insert a node immediately after head (MRU position).
   *
   * Before: head <-> [first] <-> ...
   * After:  head <-> [node] <-> [first] <-> ...
   */
  private insertAtFront(node: CacheNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Splice a node out of its current position.
   *
   * Before: [prev] <-> [node] <-> [next]
   * After:  [prev] <-> [next]
   */
  private removeNode(node: CacheNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Dangle pointers to help GC
    node.prev = null;
    node.next = null;
  }

  /** Splice out + reinsert at front in two clean steps */
  private moveToFront(node: CacheNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /** Remove tail.prev — the true LRU node */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;

    // Guard: only sentinels remain (capacity = 0 case, blocked by constructor)
    if (lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
    this.stats.evictions++;
  }
}
