## Full Implementation

```typescript
/**
 * Doubly Linked List Node
 * Stores both key and value so we can delete from the HashMap
 * when evicting from the tail (we need the key to do that)
 */
class DLLNode<K, V> {
  key: K;
  value: V;
  prev: DLLNode<K, V> | null = null;
  next: DLLNode<K, V> | null = null;

  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
}

/**
 * LRU Cache with O(1) get and put operations
 *
 * Invariant: HEAD.next = most recently used, TAIL.prev = least recently used
 */
class LRUCache<K, V> {
  private readonly capacity: number;
  private readonly map: Map<K, DLLNode<K, V>>;

  // Sentinel nodes eliminate null checks on boundary conditions
  private readonly head: DLLNode<K, V>; // dummy head (MRU side)
  private readonly tail: DLLNode<K, V>; // dummy tail (LRU side)

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Initialize sentinel nodes — they never hold real data
    this.head = new DLLNode<K, V>(null as K, null as V);
    this.tail = new DLLNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Returns the value for `key`, or undefined if not present.
   * Marks the accessed entry as most recently used.
   * Time: O(1) | Space: O(1)
   */
  get(key: K): V | undefined {
    const node = this.map.get(key);
    if (!node) return undefined;

    // Accessing promotes this node to MRU position
    this.promoteToFront(node);
    return node.value;
  }

  /**
   * Inserts or updates `key` with `value`.
   * If at capacity, evicts the least recently used entry first.
   * Time: O(1) | Space: O(1)
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      // Update value in-place and promote to MRU
      existing.value = value;
      this.promoteToFront(existing);
      return;
    }

    // Evict LRU entry if we're at capacity
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    const newNode = new DLLNode(key, value);
    this.map.set(key, newNode);
    this.insertAtFront(newNode);
  }

  /**
   * Removes a key from the cache explicitly.
   * Returns true if the key existed, false otherwise.
   * Time: O(1) | Space: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeFromList(node);
    this.map.delete(key);
    return true;
  }

  /**
   * Removes all entries from the cache.
   * Time: O(1) | Space: O(1)
   */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Introspection ─────────────────────────────────────────────────────────

  /** Current number of entries */
  get size(): number {
    return this.map.size;
  }

  /** Whether a key exists (does NOT update recency) */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /**
   * Returns keys from most-recently-used to least-recently-used.
   * Useful for debugging and testing.
   */
  keys(): K[] {
    const result: K[] = [];
    let curr = this.head.next;
    while (curr !== this.tail) {
      result.push(curr!.key);
      curr = curr!.next;
    }
    return result;
  }

  toString(): string {
    return `LRUCache(${this.size}/${this.capacity}) [${this.keys().join(" → ")}]`;
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /**
   * Inserts a node immediately after the head sentinel (MRU position).
   *
   *  Before: HEAD ⟺ [first] ...
   *  After:  HEAD ⟺ [node] ⟺ [first] ...
   */
  private insertAtFront(node: DLLNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Removes a node from its current position in the list.
   * Works for any node except the sentinels.
   */
  private removeFromList(node: DLLNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Null out pointers to help GC and catch bugs early
    node.prev = null;
    node.next = null;
  }

  /** Move an existing node to the MRU position */
  private promoteToFront(node: DLLNode<K, V>): void {
    this.removeFromList(node);
    this.insertAtFront(node);
  }

  /**
   * Evicts the least recently used entry (node before tail sentinel).
   * Also removes it from the HashMap using the node's stored key.
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev!;
    // tail.prev is always a real node when size > 0 (enforced by capacity check)
    this.removeFromList(lruNode);
    this.map.delete(lruNode.key);
  }
}
