# LRU Cache Implementation in TypeScript

## Data Structure Choice

An LRU cache requires O(1) for both operations, which rules out arrays (O(n) removal). The optimal solution combines:

- **HashMap**: O(1) key lookup
- **Doubly Linked List**: O(1) insertion/deletion at any position (given a node reference)

The map stores `key → node` pairs, while the list maintains access order (most recent at head, least recent at tail).

```typescript
// ============================================================
// Node definition for the doubly linked list
// ============================================================
class DLinkedNode<V> {
  key: number;
  value: V;
  prev: DLinkedNode<V> | null = null;
  next: DLinkedNode<V> | null = null;

  constructor(key: number = 0, value: V = undefined as V) {
    this.key = key;
    this.value = value;
  }
}

// ============================================================
// LRU Cache Implementation
// ============================================================
class LRUCache<V = number> {
  private capacity: number;
  private size: number = 0;
  private cache: Map<number, DLinkedNode<V>>;

  // Sentinel nodes eliminate null-checks on list boundaries
  private head: DLinkedNode<V>; // Most recently used side
  private tail: DLinkedNode<V>; // Least recently used side

  constructor(capacity: number) {
    if (capacity <= 0 || !Number.isInteger(capacity)) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.cache = new Map();

    // Initialize sentinel head and tail
    this.head = new DLinkedNode<V>();
    this.tail = new DLinkedNode<V>();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ── Public API ────────────────────────────────────────────

  /**
   * Retrieve value by key.
   * Moves the accessed node to the front (most recently used).
   * Returns -1 if the key doesn't exist.
   * Time: O(1)
   */
  get(key: number): V | -1 {
    const node = this.cache.get(key);

    if (!node) return -1;

    // Mark as most recently used
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * - Update: refresh value and move to front.
   * - Insert: add to front; evict LRU if over capacity.
   * Time: O(1)
   */
  put(key: number, value: V): void {
    const existingNode = this.cache.get(key);

    if (existingNode) {
      // Update existing entry
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Insert new entry
    const newNode = new DLinkedNode<V>(key, value);
    this.cache.set(key, newNode);
    this.addToFront(newNode);
    this.size++;

    // Evict LRU entry if over capacity
    if (this.size > this.capacity) {
      const evicted = this.removeLRU();
      if (evicted) {
        this.cache.delete(evicted.key);
        this.size--;
      }
    }
  }

  // ── Introspection (useful for debugging/testing) ──────────

  /** Current number of entries in the cache */
  getSize(): number {
    return this.size;
  }

  /** Returns keys from most-recently-used to least-recently-used */
  keys(): number[] {
    const result: number[] = [];
    let current = this.head.next;

    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }

    return result;
  }

  // ── Private list operations ───────────────────────────────

  /** Insert a node immediately after the head sentinel */
  private addToFront(node: DLinkedNode<V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Remove an arbitrary node from the list */
  private removeNode(node: DLinkedNode<V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Nullify pointers to prevent memory leaks
    node.prev = null;
    node.next = null;
  }

  /** Move an existing node to the front (most recently used) */
  private moveToFront(node: DLinkedNode<V>): void {
    this.removeNode(node);
    this.addToFront(node);
  }

  /** Remove and return the node just before the tail sentinel (LRU) */
  private removeLRU(): DLinkedNode<V> | null {
    const lru = this.tail.prev;

    // Guard: list is empty (only sentinels remain)
    if (lru === this.head) return null;

    this.removeNode(lru!);
    return lru;
  }
}
