    }

    // Evict LRU entry if at capacity
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    // Insert new node at MRU position
    const node = new LRUNode(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  /**
   * Removes a specific key from the cache.
   * Returns true if the key existed, false otherwise.
   * Time: O(1) | Space: O(1)
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (node === undefined) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /**
   * Removes all entries from the cache.
   * Time: O(1) | Space: O(1)
   */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Introspection ────────────────────────────────────────────────────────

  /** Current number of entries in the cache. */
  get size(): number {
    return this.map.size;
  }

  /** Maximum number of entries this cache will hold. */
  get maxCapacity(): number {
    return this.capacity;
  }

  /** Returns true if the key exists (without affecting recency). */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /**
   * Returns keys in MRU → LRU order (for debugging/testing).
   * Time: O(n)
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ─── Private Helpers ──────────────────────────────────────────────────────

  /**
   * Inserts a node immediately after HEAD (MRU position).
   *
   *  Before: HEAD <-> oldFirst <-> ...
   *  After:  HEAD <-> node <-> oldFirst <-> ...
   */
  private insertAtFront(node: LRUNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /**
   * Splices a node out of its current list position.
   * Works for any interior node; sentinels are never passed here.
   *
   *  Before: prev <-> node <-> next
   *  After:  prev <-> next
   */
  private removeNode(node: LRUNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Null out pointers to help GC and prevent stale references
    node.prev = null;
    node.next = null;
  }

  /** Moves an existing node to the MRU position in O(1). */
  private moveToFront(node: LRUNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  /**
   * Removes the node just before TAIL (LRU position) and
   * deletes its key from the HashMap.
   */
  private evictLRU(): void {
    const lruNode = this.tail.prev;

    // Sentinel guard: only evict real nodes
    if (lruNode === null || lruNode === this.head) return;

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
