# LRU Cache Implementation in TypeScript

## Data Structure Choice

The key insight is combining two structures:
- **HashMap** → O(1) key lookup
- **Doubly Linked List** → O(1) insertion/deletion at any position

Together they give us O(1) get and put. A singly linked list would require O(n) deletion since we can't access a node's previous pointer.

```typescript
/**
 * Node in our doubly linked list
 * Each node holds a key (for reverse-lookup during eviction) and its value
 */
class DLLNode<K, V> {
  constructor(
    public key: K,
    public value: V,
    public prev: DLLNode<K, V> | null = null,
    public next: DLLNode<K, V> | null = null
  ) {}
}

/**
 * LRU Cache — O(1) get and put
 *
 * Mental model:
 *   [HEAD] <-> [most recent] <-> ... <-> [least recent] <-> [TAIL]
 *
 * HEAD and TAIL are sentinel nodes (no real data).
 * "Most recent" lives just after HEAD.
 * "Least recent" lives just before TAIL (first eviction candidate).
 */
class LRUCache<K = number, V = number> {
  private capacity: number;
  private map: Map<K, DLLNode<K, V>>;
  private head: DLLNode<K, V>; // sentinel: most-recent boundary
  private tail: DLLNode<K, V>; // sentinel: least-recent boundary

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity <= 0) {
      throw new RangeError(`Capacity must be a positive integer, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinels eliminate all null-checks during insert/remove
    this.head = new DLLNode<K, V>(null as K, null as V);
    this.tail = new DLLNode<K, V>(null as K, null as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Returns the value if key exists, -1 otherwise.
   * Accessing a key makes it the most recently used.
   * O(1)
   */
  get(key: K): V | -1 {
    const node = this.map.get(key);
    if (!node) return -1;

    this.moveToFront(node); // mark as recently used
    return node.value;
  }

  /**
   * Inserts or updates a key-value pair.
   * If at capacity, evicts the least recently used entry first.
   * O(1)
   */
  put(key: K, value: V): void {
    const existing = this.map.get(key);

    if (existing) {
      existing.value = value;   // update in-place
      this.moveToFront(existing);
      return;
    }

    // Evict before inserting so we never exceed capacity
    if (this.map.size === this.capacity) {
      this.evictLRU();
    }

    const node = new DLLNode(key, value);
    this.map.set(key, node);
    this.insertAtFront(node);
  }

  /** Current number of entries */
  get size(): number {
    return this.map.size;
  }

  /** Peek at order without affecting recency — useful for debugging */
  toOrderedArray(): Array<{ key: K; value: V }> {
    const result: Array<{ key: K; value: V }> = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push({ key: current!.key, value: current!.value });
      current = current!.next;
    }
    return result; // index 0 = most recent, last index = least recent
  }

  // ─── Private Helpers ───────────────────────────────────────────────────────

  /** Detach a node from wherever it sits in the list. O(1) */
  private remove(node: DLLNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Leave node.prev/next intact — caller decides what to do next
  }

  /** Place a node immediately after HEAD (most-recent position). O(1) */
  private insertAtFront(node: DLLNode<K, V>): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  /** Combined remove + insertAtFront. O(1) */
  private moveToFront(node: DLLNode<K, V>): void {
    this.remove(node);
    this.insertAtFront(node);
  }

  /** Remove the node just before TAIL (least-recently used). O(1) */
  private evictLRU(): void {
    const lru = this.tail.prev!;
    // Guard: only evict real nodes (capacity ≥ 1, so sentinels never touch)
    if (lru === this.head) return;

    this.remove(lru);
    this.map.delete(lru.key);
  }
}
