    if (!node) return undefined;

    // Move to front (mark as recently used)
    this.moveToFront(node);
    return node.value;
  }

  /**
   * Insert or update a key-value pair.
   * Evicts least recently used item if at capacity.
   * O(1) time complexity.
   */
  put(key: K, value: V): void {
    const existingNode = this.map.get(key);

    if (existingNode) {
      // Update value and mark as recently used
      existingNode.value = value;
      this.moveToFront(existingNode);
      return;
    }

    // Evict LRU item if at capacity
    if (this.map.size >= this.capacity) {
      this.evictLRU();
    }

    // Insert new node at front
    const newNode = new ListNode(key, value);
    this.map.set(key, newNode);
    this.insertAtFront(newNode);
  }

  /**
   * Explicitly remove a key from the cache.
   * Returns true if the key existed, false otherwise.
   */
  delete(key: K): boolean {
    const node = this.map.get(key);
    if (!node) return false;

    this.removeNode(node);
    this.map.delete(key);
    return true;
  }

  /**
   * Returns current number of items in cache.
   */
  get size(): number {
    return this.map.size;
  }

  /**
   * Check if a key exists without affecting recency order.
   */
  has(key: K): boolean {
    return this.map.has(key);
  }

  /**
   * Clear all entries.
   */
  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  /**
   * Returns keys from most recently used to least recently used.
   */
  keys(): K[] {
    const result: K[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      result.push(current!.key);
      current = current!.next;
    }
    return result;
  }

  // ─── Private Helpers ────────────────────────────────────────────────────────

  private insertAtFront(node: ListNode<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: ListNode<K, V>): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    // Prevent memory leaks by clearing references
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: ListNode<K, V>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lruNode = this.tail.prev!;
    if (lruNode === this.head) return; // Cache is empty

    this.removeNode(lruNode);
    this.map.delete(lruNode.key);
  }
}
```

---

## Edge Cases Handled

| Edge Case | Handling |
|-----------|----------|
| `get` on missing key | Returns `undefined` |
| `put` existing key | Updates value, refreshes recency |
| Capacity = 1 | Evicts on every new unique key |
| Evict from empty cache | Guard `lruNode === this.head` |
| `capacity <= 0` | Throws `Error` in constructor |
| Memory leaks on remove | Clears `prev`/`next` references |

