## Usage & Tests

```typescript
// ─── Basic Usage ─────────────────────────────────────────────────────────────
const cache = new LRUCache<string, number>(3);

cache.put("a", 1);
cache.put("b", 2);
cache.put("c", 3);

console.log(cache.get("a"));    // 1  — "a" is now MRU
console.log(cache.keys());      // ["a", "c", "b"]

cache.put("d", 4);              // evicts "b" (LRU)
console.log(cache.has("b"));    // false
console.log(cache.keys());      // ["d", "a", "c"]

// ─── Update existing key ──────────────────────────────────────────────────────
cache.put("a", 99);
console.log(cache.get("a"));    // 99
console.log(cache.keys());      // ["a", "d", "c"]

// ─── Capacity 1 edge case ─────────────────────────────────────────────────────
const tiny = new LRUCache<number, string>(1);
tiny.put(1, "one");
tiny.put(2, "two");             // evicts 1
console.log(tiny.get(1));       // undefined
console.log(tiny.get(2));       // "two"

// ─── Delete ───────────────────────────────────────────────────────────────────
cache.delete("d");
console.log(cache.size);        // 2
console.log(cache.has("d"));    // false

// ─── Invalid capacity ─────────────────────────────────────────────────────────
try {
  new LRUCache(0);
} catch (e) {
  console.log((e as Error).message); // "Capacity must be a positive integer"
}
